let _hapticLabel: HTMLLabelElement | null = null
function _getHapticLabel(): HTMLLabelElement | null {
    if (typeof document === "undefined") return null
    if (_hapticLabel) return _hapticLabel
    const input = document.createElement("input")
    input.type = "checkbox"
    input.id = "curastem-haptic-switch"
    input.setAttribute("switch", "")
    input.style.display = "none"
    document.body.appendChild(input)
    const label = document.createElement("label")
    label.htmlFor = "curastem-haptic-switch"
    label.style.display = "none"
    document.body.appendChild(label)
    _hapticLabel = label
    return label
}

function _iosHaptic(times: number, gapMs = 0): void {
    const label = _getHapticLabel()
    if (!label) return
    if (times === 1) {
        label.click()
        return
    }
    let n = 0
    const fire = () => {
        label.click()
        if (++n < times) setTimeout(fire, gapMs)
    }
    fire()
}

const haptic = {
    light: () => {
        navigator.vibrate?.(10)
        _iosHaptic(1)
    },
    medium: () => {
        navigator.vibrate?.(20)
        _iosHaptic(1)
    },
    heavy: () => {
        navigator.vibrate?.(40)
        _iosHaptic(1)
    },
    success: () => {
        navigator.vibrate?.([10, 50, 10])
        _iosHaptic(2, 60)
    },
    warning: () => {
        navigator.vibrate?.(30)
        _iosHaptic(1)
    },
    error: () => {
        navigator.vibrate?.([50, 30, 50])
        _iosHaptic(3, 40)
    },
    selection: () => {
        navigator.vibrate?.(5)
        _iosHaptic(1)
    },
}

/** iOS Safari auto-zooms focused inputs when font-size is below 16px */
function iosSafariInputFontPx(): 14 | 16 {
    if (typeof navigator === "undefined") return 14
    return /iPhone|iPad|iPod/.test(navigator.userAgent) ? 16 : 14
}





const _makeCtx = (): AudioContext | null => {
    if (typeof window === "undefined") return null
    try {
        if ("audioSession" in navigator)
            (navigator as any).audioSession.type = "play-and-record"
        const AC = window.AudioContext ?? (window as any).webkitAudioContext
        if (!AC) return null
        const ctx = new AC() as AudioContext
        ctx.resume()
        return ctx
    } catch (_) {
        return null
    }
}

const _withCompressor = (ctx: AudioContext) => {
    const comp = ctx.createDynamicsCompressor()
    comp.threshold.value = -18
    comp.knee.value = 8
    comp.ratio.value = 6
    comp.attack.value = 0.003
    comp.release.value = 0.15
    comp.connect(ctx.destination)
    return comp
}


const playCallStartSound = (): void => {
    const ctx = _makeCtx()
    if (!ctx) return
    try {
        const now = ctx.currentTime
        const out = _withCompressor(ctx)
        ;[523, 659, 784, 1047].forEach((freq, i) => {
            const osc = ctx.createOscillator(),
                gain = ctx.createGain()
            const t = now + i * 0.1
            osc.type = "sine"
            osc.frequency.setValueAtTime(freq, t)
            osc.frequency.linearRampToValueAtTime(freq * 1.04, t + 0.25)
            gain.gain.setValueAtTime(0.0001, t)
            gain.gain.linearRampToValueAtTime(0.55, t + 0.04)
            gain.gain.exponentialRampToValueAtTime(0.0001, t + 0.6)
            osc.connect(gain)
            gain.connect(out)
            osc.start(t)
            osc.stop(t + 0.65)
        })
        setTimeout(() => {
            try {
                ctx.close()
            } catch (_) {}
        }, 1400)
    } catch (_) {}
}


const playCallEndSound = (): void => {
    const ctx = _makeCtx()
    if (!ctx) return
    try {
        const now = ctx.currentTime
        const out = _withCompressor(ctx)
        ;[392, 330, 262].forEach((freq, i) => {
            const osc = ctx.createOscillator(),
                gain = ctx.createGain()
            const t = now + i * 0.13
            osc.type = "sine"
            osc.frequency.setValueAtTime(freq, t)
            osc.frequency.linearRampToValueAtTime(freq * 0.97, t + 0.45)
            gain.gain.setValueAtTime(0.0001, t)
            gain.gain.linearRampToValueAtTime(0.45, t + 0.05)
            gain.gain.exponentialRampToValueAtTime(0.0001, t + 0.6)
            osc.connect(gain)
            gain.connect(out)
            osc.start(t)
            osc.stop(t + 0.6)
        })
        setTimeout(() => {
            try {
                ctx.close()
            } catch (_) {}
        }, 1200)
    } catch (_) {}
}

