const GEOLOCATION_STORAGE_KEY = "user_location_info"
const GEOLOCATION_REFRESH_INTERVAL_MS = 24 * 60 * 60 * 1000

interface LocationInfo {
    city?: string
    region?: string
    country?: string
    lat?: number
    lng?: number
}

interface CachedLocation extends LocationInfo {
    fetchedAt: number
}

function readLocationCache(): CachedLocation | null {
    if (typeof window === "undefined") return null
    try {
        const raw = localStorage.getItem(GEOLOCATION_STORAGE_KEY)
        if (!raw) return null
        const parsed = JSON.parse(raw) as Partial<CachedLocation>
        return parsed.city != null || parsed.lat != null
            ? (parsed as CachedLocation)
            : null
    } catch {
        return null
    }
}

function writeLocationCache(info: LocationInfo): void {
    if (typeof window === "undefined") return
    try {
        localStorage.setItem(
            GEOLOCATION_STORAGE_KEY,
            JSON.stringify({ ...info, fetchedAt: Date.now() })
        )
    } catch {}
}

// Fetches location from our Cloudflare Worker /geo endpoint — the edge
// already knows lat/lng from CF-IPCountry without an external API call.
async function fetchGeolocationFromAPI(apiBase: string): Promise<LocationInfo | null> {
    try {
        const res = await fetch(`${apiBase}/geo`)
        if (!res.ok) return null
        const data = await res.json() as { lat?: number; lng?: number; city?: string; region?: string; country?: string }
        if (data.lat == null && data.city == null) return null
        return {
            city: data.city ?? undefined,
            region: data.region ?? undefined,
            country: data.country ?? undefined,
            lat: data.lat ?? undefined,
            lng: data.lng ?? undefined,
        }
    } catch {
        return null
    }
}

/** Fallback when stream omits thoughtSignature (Gemini 3 requires it for follow-up). */
const GEMINI_THOUGHT_SIGNATURE_SKIP = "skip_thought_signature_validator"

// On-device favorite-things (memories) & resume storage (localStorage)
// Each line is prefixed with "- ". The AI uses 0-based line indexes as IDs.

/** Returns all non-empty bullet lines from you_interests. */
const getMemories = (): string[] => {
    try {
        if (typeof window === "undefined") return []
        const raw = localStorage.getItem("you_interests") || ""
        return raw
            .split("\n")
            .map((l) => l.trim())
            .filter(Boolean)
    } catch {
        return []
    }
}

/**
 * Appends a new bullet line to you_interests (deduplicates case-insensitively).
 * Returns the full updated string.
 */
const saveMemory = (text: string): string => {
    const line = text.startsWith("- ") ? text : `- ${text}`
    try {
        const existing = getMemories()
        const lower = line.toLowerCase()
        if (existing.some((l) => l.toLowerCase() === lower))
            return existing.join("\n")
        const updated = [...existing, line]
        localStorage.setItem("you_interests", updated.join("\n"))
        return updated.join("\n")
    } catch {
        return line
    }
}

/**
 * Edits or deletes a bullet line by its 0-based index.
 * Pass newText=null to delete. Returns the full updated string.
 */
const updateMemory = (index: number, newText: string | null): string => {
    try {
        const existing = getMemories()
        let updated: string[]
        if (newText === null) {
            updated = existing.filter((_, i) => i !== index)
        } else {
            const line = newText.startsWith("- ") ? newText : `- ${newText}`
            updated = existing.map((l, i) => (i === index ? line : l))
        }
        const joined = updated.join("\n")
        localStorage.setItem("you_interests", joined)
        return joined
    } catch {
        return ""
    }
}

/** Plain text from stored resume HTML (or DocEditor) for prompts and retrieve_resume. */
function htmlToPlainResumeText(html: string): string {
    if (typeof document === "undefined") return html
    const div = document.createElement("div")
    div.innerHTML = html
    return (div.innerText || "").replace(/\r\n/g, "\n")
}

const getResume = (): string | null => {
    try {
        if (typeof window === "undefined") return null
        const html = localStorage.getItem("curastem_resume_doc_html")
        if (html?.trim()) return htmlToPlainResumeText(html)
        return localStorage.getItem("curastem_resume")
    } catch {
        return null
    }
}

/** Plain text from chat `save_resume`; clears structured profile HTML so one source wins. */
const saveResume = (content: string): void => {
    try {
        localStorage.setItem("curastem_resume", content)
        localStorage.removeItem("curastem_resume_doc_html")
    } catch {}
}

/** Plain text from profile storage → minimal HTML for DocEditor. */
function plainTextToResumeDocHtml(text: string): string {
    const normalized = text.replace(/\r\n/g, "\n")
    if (!normalized.trim()) return "<p></p>"
    return normalized
        .split("\n")
        .map((line) => {
            if (!line.length) return "<p><br></p>"
            const esc = line
                .replace(/&/g, "&amp;")
                .replace(/</g, "&lt;")
                .replace(/>/g, "&gt;")
            return `<p>${esc}</p>`
        })
        .join("")
}

/** Curastem doc editor: Title (h1), section lines (h1.doc-block-section), and paragraphs only — no h2/h3/h4. */
const DOC_EDITOR_HTML_BLOCK_RULES = `<h1> or <h1 class="doc-block-title"> (title); <h1 class="doc-block-section"> (sections); <p>, <ul>/<li>, <b>/<strong>, <a>. No <h2>-<h4>.`

