const useChatIconAnimation = () => {
    const [currentState, setCurrentState] = React.useState(
        CHAT_INPUT_EYE_STATES.LOOKING
    )
    const [isMounted, setIsMounted] = React.useState(false)
    const hasInteractedRef = React.useRef(false)
    const isLookingDownRef = React.useRef(false)
    const timeoutIdsRef = React.useRef<any[]>([])

    React.useEffect(() => {
        const delayTimer = setTimeout(() => setIsMounted(true), 200)
        return () => clearTimeout(delayTimer)
    }, [])

    React.useEffect(() => {
        const handleInteraction = () => {
            if (hasInteractedRef.current) return
            hasInteractedRef.current = true

            timeoutIdsRef.current.forEach((id) => {
                if (id) clearTimeout(id)
            })
            timeoutIdsRef.current = []

            setCurrentState(CHAT_INPUT_EYE_STATES.LOOKING)
        }

        const events = ["mousedown", "touchstart", "keydown", "click"]
        events.forEach((e) =>
            document.addEventListener(e, handleInteraction, { once: true })
        )
        return () =>
            events.forEach((e) =>
                document.removeEventListener(e, handleInteraction)
            )
    }, [])

    React.useEffect(() => {
        
        if (hasInteractedRef.current) return

        const scheduleAnimation = (
            state: any,
            blinkState: any,
            nextState: any,
            toggleDirection: boolean
        ) => {
            if (hasInteractedRef.current) return
            setCurrentState(state)

            const blinkDelay =
                EYE_ANIMATION_CONFIG.BLINK_INTERVAL_MIN +
                Math.random() *
                    (EYE_ANIMATION_CONFIG.BLINK_INTERVAL_MAX -
                        EYE_ANIMATION_CONFIG.BLINK_INTERVAL_MIN)
            const timeoutId1 = setTimeout(() => {
                if (hasInteractedRef.current) return
                setCurrentState(blinkState)
                const timeoutId2 = setTimeout(() => {
                    if (hasInteractedRef.current) return
                    setCurrentState(state)

                    const transitionDelay =
                        EYE_ANIMATION_CONFIG.BLINK_INTERVAL_MIN +
                        Math.random() *
                            (EYE_ANIMATION_CONFIG.BLINK_INTERVAL_MAX -
                                EYE_ANIMATION_CONFIG.BLINK_INTERVAL_MIN)
                    const timeoutId3 = setTimeout(() => {
                        if (hasInteractedRef.current) return
                        isLookingDownRef.current = toggleDirection
                        animateLoop()
                    }, transitionDelay)
                    timeoutIdsRef.current.push(timeoutId3)
                }, EYE_ANIMATION_CONFIG.BLINK_DURATION)
                timeoutIdsRef.current.push(timeoutId2)
            }, blinkDelay)
            timeoutIdsRef.current.push(timeoutId1)
        }

        const animateLoop = () => {
            if (hasInteractedRef.current) return
            if (isLookingDownRef.current) {
                scheduleAnimation(
                    CHAT_INPUT_EYE_STATES.LOOKING_DOWN,
                    CHAT_INPUT_EYE_STATES.BLINKING_LOOKING_DOWN,
                    CHAT_INPUT_EYE_STATES.LOOKING,
                    false
                )
            } else {
                scheduleAnimation(
                    CHAT_INPUT_EYE_STATES.LOOKING,
                    CHAT_INPUT_EYE_STATES.BLINKING_LOOKING,
                    CHAT_INPUT_EYE_STATES.LOOKING_DOWN,
                    true
                )
            }
        }

        
        animateLoop()

        return () => {
            
            timeoutIdsRef.current.forEach((id) => {
                if (id) clearTimeout(id)
            })
            timeoutIdsRef.current = []
        }
    }, [])

    return { currentState, isMounted }
}

