// --- HELPER: DEBUG PANEL (shared chrome for P2P vs Tools & MCP) ---
function DebugPanel({
    title,
    position,
    logs,
    themeColors,
    meta,
    onClear,
}: {
    title: string
    position: "left" | "right"
    logs: string[]
    themeColors: typeof darkColors
    meta: React.ReactNode
    onClear: () => void
}) {
    const scrollRef = React.useRef<HTMLDivElement>(null)
    const [copied, setCopied] = React.useState(false)

    React.useEffect(() => {
        if (scrollRef.current) {
            scrollRef.current.scrollTop = scrollRef.current.scrollHeight
        }
    }, [logs])

    const handleCopy = () => {
        const logsText = logs.join("\n")
        navigator.clipboard
            .writeText(logsText)
            .then(() => {
                setCopied(true)
                setTimeout(() => setCopied(false), 2000)
            })
            .catch((err) => {
                console.error("Failed to copy logs:", err)
            })
    }

    const btnStyle: React.CSSProperties = {
        background: themeColors.semantic.accent,
        color: themeColors.text.primary,
        border: "none",
        borderRadius: 6,
        padding: "4px 8px",
        fontSize: 10,
        cursor: "pointer",
        fontWeight: "600",
        transition: "all 0.2s",
        flexShrink: 0,
        display: "flex",
        alignItems: "center",
        justifyContent: "center",
        minWidth: 28,
        minHeight: 28,
    }

    return (
        <motion.div
            drag
            dragMomentum={false}
            dragElastic={0.1}
            style={{
                position: "fixed",
                bottom: 20,
                ...(position === "left" ? { left: 20 } : { right: 20 }),
                width: 380,
                height: 440,
                background: themeColors.surfaceHighlight,
                color: themeColors.text.secondary,
                fontFamily: "monospace",
                fontSize: 12,
                padding: 12,
                overflow: "hidden",
                zIndex: 9999,
                pointerEvents: "auto",
                borderRadius: 28,
                display: "flex",
                flexDirection: "column",
                cursor: "grab",
            }}
            whileDrag={{ cursor: "grabbing", scale: 1.01 }}
        >
            <div
                style={{
                    display: "flex",
                    flexDirection: "column",
                    gap: 6,
                    marginBottom: 8,
                    paddingBottom: 8,
                    flexShrink: 0,
                }}
            >
                {meta}
            </div>

            <div
                style={{
                    display: "flex",
                    justifyContent: "space-between",
                    alignItems: "center",
                    marginBottom: 6,
                    flexShrink: 0,
                    gap: 8,
                }}
            >
                <div
                    style={{
                        color: themeColors.text.primary,
                        fontWeight: "bold",
                        fontSize: 13,
                        minWidth: 0,
                    }}
                >
                    {title}
                </div>
                <div
                    style={{
                        display: "flex",
                        alignItems: "center",
                        gap: 6,
                        flexShrink: 0,
                    }}
                >
                    <button
                        type="button"
                        title="Clear log"
                        aria-label="Clear log"
                        onClick={(e) => {
                            e.stopPropagation()
                            onClear()
                        }}
                        style={btnStyle}
                    >
                        <svg
                            width="14"
                            height="14"
                            viewBox="0 0 24 24"
                            fill="none"
                            stroke="currentColor"
                            strokeWidth="2"
                            strokeLinecap="round"
                            strokeLinejoin="round"
                            aria-hidden
                        >
                            <path d="M21 12a9 9 0 1 1-3-6.7L21 8" />
                            <path d="M21 3v5h-5" />
                        </svg>
                    </button>
                    <button
                        type="button"
                        onClick={(e) => {
                            e.stopPropagation()
                            handleCopy()
                        }}
                        style={{
                            ...btnStyle,
                            background: copied
                                ? themeColors.coloredAccents.rainbow[3]
                                : themeColors.semantic.accent,
                            minWidth: "auto",
                            padding: "4px 10px",
                        }}
                    >
                        {copied ? "✓ Copied" : "Copy"}
                    </button>
                </div>
            </div>

            <div
                ref={scrollRef}
                style={{
                    flex: 1,
                    overflowY: "auto",
                    fontSize: 11,
                    lineHeight: 1.3,
                }}
            >
                {logs.slice(-100).map((line, i) => (
                    <div
                        key={i}
                        style={{ marginBottom: 3, wordBreak: "break-word" }}
                    >
                        {line}
                    </div>
                ))}
            </div>
        </motion.div>
    )
}


interface ReportModalProps {
    isOpen: boolean
    onClose: () => void
    onSubmit: (reason: string) => void
    participantCount?: number
    themeColors?: typeof darkColors
    reportType?: "user" | "chat"
    /** Pull-to-dismiss motion value driven by the parent (mobile only) */
    dragY?: ReturnType<typeof useMotionValue<number>>
}

/** 1 */
function CheckmarkIcon({
    size = 14,
    color = "#000",
}: {
    size?: number
    color?: string
}) {
    return (
        <svg
            width={size}
            height={size}
            viewBox="0 0 16 16"
            fill="none"
            xmlns="http://www.w3.org/2000/svg"
            aria-hidden="true"
        >
            <path
                d="M3 8.5L6.5 12L13 5"
                stroke={color}
                strokeWidth="1.2"
                strokeLinecap="round"
                strokeLinejoin="round"
            />
        </svg>
    )
}

function ReportModal({
    isOpen,
    onClose,
    onSubmit,
    participantCount = 2,
    themeColors = darkColors,
    reportType = "user",
    dragY,
}: ReportModalProps) {
    const [selected, setSelected] = React.useState<string | null>(null)
    const [hoveredRow, setHoveredRow] = React.useState<string | null>(null)
    const [isCloseHovered, setIsCloseHovered] = React.useState(false)
    
    
    const [justSubmitted, setJustSubmitted] = React.useState(false)
    const submitTimerRef = React.useRef<number | null>(null)

    const reasons = [
        "Violence & self-harm",
        "Sexual exploitation & abuse",
        "Child/teen exploitation",
        "Bullying & harassment",
        "Spam, fraud & deception",
        "Privacy violation",
        "Intellectual property",
        "Age-inappropriate content",
        "Something else",
    ]

    React.useEffect(() => {
        if (!isOpen) {
            setSelected(null)
            setJustSubmitted(false)
            if (submitTimerRef.current != null) {
                window.clearTimeout(submitTimerRef.current)
                submitTimerRef.current = null
            }
        }
    }, [isOpen])

    React.useEffect(() => {
        return () => {
            if (submitTimerRef.current != null) {
                window.clearTimeout(submitTimerRef.current)
            }
        }
    }, [])

    const handleSubmit = React.useCallback(() => {
        if (!selected || justSubmitted) return
        setJustSubmitted(true)
        submitTimerRef.current = window.setTimeout(() => {
            submitTimerRef.current = null
            onSubmit(selected)
        }, 1000)
    }, [selected, justSubmitted, onSubmit])

    const handleBackdropClick = (e: React.MouseEvent) => {
        if (e.target === e.currentTarget) onClose()
    }

    const isMobileLayout =
        typeof window !== "undefined" && window.innerWidth < 768
    const isMultiParty = participantCount > 2
    const title = reportType === "chat" ? "Report chat" : "Report user"
    const question =
        reportType === "chat"
            ? isMultiParty
                ? "Why are you reporting this chat? User in violation will be banned."
                : "Why are you reporting this chat?"
            : isMultiParty
              ? "Why are you reporting this user? User in violation will be banned."
              : "Why are you reporting this user?"

    return (
        <ModalSheet
            isOpen={isOpen}
            onClose={onClose}
            themeColors={themeColors}
            zIndex={10000}
            className="ReportOverlay"
            dragY={isMobileLayout ? dragY : undefined}
            sheetStyle={{
                flex: "none",
                width: isMobileLayout ? "100%" : 400,
                height: isMobileLayout ? "calc(100% - 16px)" : "auto",
                maxWidth: isMobileLayout ? "none" : 400,
                maxHeight: isMobileLayout ? "none" : 600,
                boxShadow: "0px 4px 24px hsla(0, 0%, 0%, 0.04)",
                borderRadius: isMobileLayout ? "24px 24px 0 0" : 48,
                outline: `0.33px ${themeColors.hover.strong} solid`,
                outlineOffset: "-0.33px",
                justifyContent: "flex-start",
                alignItems: "flex-start",
            }}
        >
            {/** Floating gradient header — matches Your profile overlay */}
            <div
                data-layer="report header"
                className="ReportHeader"
                style={{
                    position: "absolute",
                    top: 0,
                    left: 0,
                    right: 0,
                    padding: isMobileLayout ? 16 : 28,
                    paddingBottom: 32,
                    background: `linear-gradient(180deg, ${themeColors.background} 72%, transparent 100%)`,
                    flexDirection: "column",
                    justifyContent: "center",
                    alignItems: "flex-start",
                    gap: 8,
                    display: "flex",
                    zIndex: 2,
                    pointerEvents: "none",
                }}
            >
                <h2
                    style={{
                        margin: 0,
                        padding: 0,
                        alignSelf: "stretch",
                        color: themeColors.text.primary,
                        fontSize: 16,
                        fontFamily: "Inter",
                        fontWeight: "400",
                        lineHeight: "16px",
                        wordWrap: "break-word",
                    }}
                >
                    {title}
                </h2>
                <div
                    style={{
                        alignSelf: "stretch",
                        justifyContent: "center",
                        display: "flex",
                        flexDirection: "column",
                        color: themeColors.text.secondary,
                        fontSize: 12,
                        fontFamily: "Inter",
                        fontWeight: "400",
                        lineHeight: "16.8px",
                        wordWrap: "break-word",
                    }}
                >
                    {question}
                </div>
                {/** Close button — re-enable pointer events since parent is none */}
                <div
                    data-svg-wrapper
                    data-layer="close report button"
                    className="CloseReportButtonHasAFillHoverEffect"
                    aria-label="Close report"
                    style={{
                        position: "absolute",
                        top: isMobileLayout ? 4 : 14,
                        right: isMobileLayout ? 8 : 16,
                        cursor: "pointer",
                        width: 36,
                        height: 36,
                        display: "flex",
                        alignItems: "center",
                        justifyContent: "center",
                        background: isCloseHovered
                            ? themeColors.hover.default
                            : "transparent",
                        borderRadius: "50%",
                        transition: "background 0.2s",
                        pointerEvents: "auto",
                    }}
                    onClick={() => {
                        haptic.light()
                        onClose()
                    }}
                    onMouseEnter={() =>
                        !isMobileLayout && setIsCloseHovered(true)
                    }
                    onMouseLeave={() => setIsCloseHovered(false)}
                >
                    <svg
                        width="36"
                        height="36"
                        viewBox="0 0 36 36"
                        fill="none"
                        xmlns="http://www.w3.org/2000/svg"
                        aria-hidden="true"
                    >
                        <path
                            d="M23.25 12.75L12.75 23.25M12.75 12.75L23.25 23.25"
                            stroke={themeColors.text.primary}
                            strokeOpacity="0.95"
                            strokeWidth="1.2"
                            strokeLinecap="round"
                            strokeLinejoin="round"
                        />
                    </svg>
                </div>
            </div>

            {/** Scroll body — paddingTop accounts for floating header */}
            <div
                className="ReportScrollBody"
                style={{
                    width: "100%",
                    
                    
                    flex: isMobileLayout ? "1 1 0" : "0 0 auto",
                    overflowY: "auto",
                    overflowX: "hidden",
                    display: "flex",
                    flexDirection: "column",
                    gap: 16,
                    paddingTop: 112,
                    
                    
                    
                    paddingBottom: isMobileLayout
                        ? "calc(72px + env(safe-area-inset-bottom, 0px) + 16px)"
                        : 28,
                    paddingLeft: isMobileLayout ? 16 : 28,
                    paddingRight: isMobileLayout ? 16 : 28,
                    boxSizing: "border-box",
                }}
            >
                <style>{`
                    .ReportScrollBody::-webkit-scrollbar { display: none; }
                `}</style>

                {/** Options List */}
                <div
                    style={{
                        display: "flex",
                        flexDirection: "column",
                    }}
                >
                    {reasons.map((reason) => (
                        <div
                            key={reason}
                            onClick={() => setSelected(reason)}
                            onMouseEnter={() => setHoveredRow(reason)}
                            onMouseLeave={() => setHoveredRow(null)}
                            style={{
                                display: "flex",
                                alignItems: "center",
                                gap: 8,
                                padding: "8px 0",
                                cursor: "pointer",
                            }}
                        >
                            <div
                                style={{
                                    width: 16,
                                    height: 16,
                                    borderRadius: "50%",
                                    border: `0.33px solid ${selected === reason ? themeColors.text.primary : themeColors.text.secondary}`,
                                    background:
                                        hoveredRow === reason
                                            ? themeColors.border.subtle
                                            : "transparent",
                                    display: "flex",
                                    alignItems: "center",
                                    justifyContent: "center",
                                    boxSizing: "border-box",
                                }}
                            >
                                {selected === reason && (
                                    <div
                                        style={{
                                            width: 7,
                                            height: 7,
                                            borderRadius: "50%",
                                            background:
                                                themeColors.text.primary,
                                        }}
                                    />
                                )}
                            </div>
                            <div
                                style={{
                                    color: themeColors.text.primary,
                                    fontSize: 15,
                                    fontFamily: "Inter",
                                    fontWeight: "400",
                                    opacity: 0.95,
                                }}
                            >
                                {reason}
                            </div>
                        </div>
                    ))}
                </div>

                {/** Desktop inline footer — right-aligned pill button */}
                {!isMobileLayout && (
                    <div
                        style={{
                            display: "flex",
                            justifyContent: "flex-end",
                            marginTop: 8,
                        }}
                    >
                        <button
                            disabled={!selected || justSubmitted}
                            onClick={handleSubmit}
                            style={{
                                padding: "10px 12px",
                                borderRadius: 28,
                                background: selected
                                    ? themeColors.text.primary
                                    : themeColors.surface,
                                color: selected
                                    ? themeColors.surfaceBlack
                                    : themeColors.text.tertiary,
                                border: "none",
                                fontSize: 14,
                                fontFamily: "Inter",
                                fontWeight: "500",
                                cursor:
                                    selected && !justSubmitted
                                        ? "pointer"
                                        : "default",
                                boxSizing: "border-box",
                                display: "inline-flex",
                                alignItems: "center",
                                justifyContent: "center",
                                gap: 6,
                            }}
                        >
                            {justSubmitted ? (
                                <>
                                    <CheckmarkIcon
                                        size={14}
                                        color={themeColors.surfaceBlack}
                                    />
                                    Reported
                                </>
                            ) : (
                                "Submit"
                            )}
                        </button>
                    </div>
                )}
            </div>

            {/** Mobile pinned full-width Submit — respects sheet side padding and safe-area inset so it sits flush at the bottom */}
            {isMobileLayout && (
                <div
                    style={{
                        position: "absolute",
                        left: 0,
                        right: 0,
                        bottom: 0,
                        padding: 16,
                        paddingBottom:
                            "calc(16px + env(safe-area-inset-bottom, 0px))",
                        boxSizing: "border-box",
                        background: themeColors.background,
                        zIndex: 2,
                    }}
                >
                    <button
                        disabled={!selected || justSubmitted}
                        onClick={handleSubmit}
                        style={{
                            width: "100%",
                            height: 48,
                            padding: "0 12px",
                            borderRadius: 28,
                            background: selected
                                ? themeColors.text.primary
                                : themeColors.surface,
                            color: selected
                                ? themeColors.surfaceBlack
                                : themeColors.text.tertiary,
                            border: "none",
                            fontSize: 15,
                            fontFamily: "Inter",
                            fontWeight: "500",
                            cursor:
                                selected && !justSubmitted
                                    ? "pointer"
                                    : "default",
                            boxSizing: "border-box",
                            display: "inline-flex",
                            alignItems: "center",
                            justifyContent: "center",
                            gap: 8,
                        }}
                    >
                        {justSubmitted ? (
                            <>
                                <CheckmarkIcon
                                    size={16}
                                    color={themeColors.surfaceBlack}
                                />
                                Reported
                            </>
                        ) : (
                            "Submit"
                        )}
                    </button>
                </div>
            )}
        </ModalSheet>
    )
}



