const FREE_GEOCODE_CACHE_KEY = "curastem_free_geocode_cache_v1"

function isValidLatLng(lat: unknown, lng: unknown): lat is number {
    return (
        typeof lat === "number" &&
        typeof lng === "number" &&
        Number.isFinite(lat) &&
        Number.isFinite(lng) &&
        lat >= -90 &&
        lat <= 90 &&
        lng >= -180 &&
        lng <= 180
    )
}

function readFreeGeocodeCache(
    query: string
): { lat: number; lng: number } | null {
    if (typeof localStorage === "undefined") return null
    try {
        const raw = localStorage.getItem(FREE_GEOCODE_CACHE_KEY)
        if (!raw) return null
        const root = JSON.parse(raw) as Record<string, { lat: number; lng: number }>
        const hit = root[query.trim().toLowerCase()]
        return isValidLatLng(hit?.lat, hit?.lng)
            ? { lat: hit.lat, lng: hit.lng }
            : null
    } catch {
        return null
    }
}

function writeFreeGeocodeCache(
    query: string,
    coords: { lat: number; lng: number }
): void {
    if (typeof localStorage === "undefined") return
    try {
        const raw = localStorage.getItem(FREE_GEOCODE_CACHE_KEY)
        const root = raw
            ? (JSON.parse(raw) as Record<string, { lat: number; lng: number }>)
            : {}
        root[query.trim().toLowerCase()] = coords
        localStorage.setItem(FREE_GEOCODE_CACHE_KEY, JSON.stringify(root))
    } catch {
        /** cache is opportunistic */
    }
}

async function geocodeLocationFree(
    query: string
): Promise<{ lat: number; lng: number } | null> {
    const trimmed = query.trim()
    if (!trimmed || /^remote(\s*[\(\-/]|$)/i.test(trimmed)) return null
    const cached = readFreeGeocodeCache(trimmed)
    if (cached) return cached

    try {
        const params = new URLSearchParams({ q: trimmed, limit: "1" })
        const res = await fetch(`https://photon.komoot.io/api/?${params}`)
        if (res.ok) {
            const data = (await res.json()) as {
                features?: Array<{
                    geometry?: { coordinates?: [number, number] }
                }>
            }
            const coords = data.features?.[0]?.geometry?.coordinates
            if (coords && isValidLatLng(coords[1], coords[0])) {
                const out = { lat: coords[1], lng: coords[0] }
                writeFreeGeocodeCache(trimmed, out)
                return out
            }
        }
    } catch {
        /** fall through to Nominatim */
    }

    try {
        const params = new URLSearchParams({
            q: trimmed,
            format: "json",
            limit: "1",
        })
        const res = await fetch(
            `https://nominatim.openstreetmap.org/search?${params}`
        )
        if (!res.ok) return null
        const data = (await res.json()) as Array<{ lat?: string; lon?: string }>
        const first = data[0]
        const lat = parseFloat(first?.lat ?? "")
        const lng = parseFloat(first?.lon ?? "")
        if (isValidLatLng(lat, lng)) {
            const out = { lat, lng }
            writeFreeGeocodeCache(trimmed, out)
            return out
        }
    } catch {
        return null
    }
    return null
}

/** Persist opened job detail so swiping away and back does not refetch */
const JOB_DETAIL_CACHE_STORAGE_KEY = "curastem_job_detail_cache_v2"
const JOB_DETAIL_CACHE_TTL_MS = 7 * 24 * 60 * 60 * 1000
const JOB_DETAIL_CACHE_MAX_JOBS = 48

type JobDetailCacheEntry = {
    t: number
    /** jobsApiUrl used for fetch — ignore entry if it changed */
    u: string
    /** true once AI enrichment fields are confirmed populated in this entry */
    aiDone: boolean
    desc: JobDescriptionDetail | null
    detailSummary: string | null
    detailCompanyDesc: string | null
    detailVisaSponsorship: string | null
    apiKeywords: string[]
    /** AI-extracted per-job location fields */
    detailExperienceYearsMin: number | null
    detailJobAddress: string | null
    detailJobCity: string | null
    detailJobState: string | null
    detailJobCountry: string | null
    detailSeniorityLevel: string | null
    detailLocations: string[] | null
    detailSalary: { display: string } | null
    detailLocationPoints: Array<{ lat: number; lng: number }> | null
    /** Full company object from the detail API response — fills gaps when opened from a chat snippet */
    company: HomepageJob["company"] | null
}

type JobDetailCacheRoot = Record<string, JobDetailCacheEntry>

function readJobDetailCache(
    jobId: string,
    jobsApiUrl: string
): JobDetailCacheEntry | null {
    if (typeof localStorage === "undefined") return null
    try {
        const raw = localStorage.getItem(JOB_DETAIL_CACHE_STORAGE_KEY)
        if (!raw) return null
        const root = JSON.parse(raw) as JobDetailCacheRoot
        const e = root[jobId]
        if (!e || typeof e.t !== "number") return null
        if (e.u !== jobsApiUrl) return null
        if (Date.now() - e.t > JOB_DETAIL_CACHE_TTL_MS) return null
        return e
    } catch {
        return null
    }
}

function writeJobDetailCache(
    jobId: string,
    jobsApiUrl: string,
    payload: Omit<JobDetailCacheEntry, "t" | "u">
): void {
    if (typeof localStorage === "undefined") return
    try {
        let root: JobDetailCacheRoot = {}
        const raw = localStorage.getItem(JOB_DETAIL_CACHE_STORAGE_KEY)
        if (raw) root = JSON.parse(raw) as JobDetailCacheRoot
        root[jobId] = {
            t: Date.now(),
            u: jobsApiUrl,
            aiDone: payload.aiDone,
            desc: payload.desc,
            detailSummary: payload.detailSummary,
            detailCompanyDesc: payload.detailCompanyDesc,
            detailVisaSponsorship: payload.detailVisaSponsorship,
            apiKeywords: Array.isArray(payload.apiKeywords)
                ? payload.apiKeywords
                : [],
            detailExperienceYearsMin: payload.detailExperienceYearsMin ?? null,
            detailJobAddress: payload.detailJobAddress ?? null,
            detailJobCity: payload.detailJobCity ?? null,
            detailJobState: payload.detailJobState ?? null,
            detailJobCountry: payload.detailJobCountry ?? null,
            detailSeniorityLevel: payload.detailSeniorityLevel ?? null,
            detailLocations: Array.isArray(payload.detailLocations)
                ? payload.detailLocations
                : null,
            detailSalary: payload.detailSalary ?? null,
            detailLocationPoints: Array.isArray(payload.detailLocationPoints)
                ? payload.detailLocationPoints
                : null,
            company: payload.company ?? null,
        }
        const ids = Object.keys(root)
        if (ids.length > JOB_DETAIL_CACHE_MAX_JOBS) {
            ids.sort((a, b) => root[a]!.t - root[b]!.t)
            const drop = ids.length - JOB_DETAIL_CACHE_MAX_JOBS
            for (let i = 0; i < drop; i++) delete root[ids[i]!]
        }
        localStorage.setItem(JOB_DETAIL_CACHE_STORAGE_KEY, JSON.stringify(root))
    } catch {
        
    }
}


const JOB_CHIP_STORE_KEY = "curastem_job_chip_store_v1"

function readJobChipStore(): Record<string, HomepageJob> {
    if (typeof localStorage === "undefined") return {}
    try {
        const raw = localStorage.getItem(JOB_CHIP_STORE_KEY)
        return raw ? (JSON.parse(raw) as Record<string, HomepageJob>) : {}
    } catch {
        return {}
    }
}

function writeJobChipStore(job: HomepageJob): void {
    if (typeof localStorage === "undefined") return
    try {
        const store = readJobChipStore()
        store[job.id] = job
        
        const ids = Object.keys(store)
        if (ids.length > 100) {
            
            delete store[ids[0]!]
        }
        localStorage.setItem(JOB_CHIP_STORE_KEY, JSON.stringify(store))
    } catch {
        
    }
}

/** In-memory + first-paint state for JobDetailScrollBody (sync hydrate from cache) */
type JobDetailHydrationState = {
    desc: JobDescriptionDetail | null
    detailSummary: string | null
    detailCompanyDesc: string | null
    detailVisaSponsorship: string | null
    loadingDesc: boolean
    apiKeywords: string[]
    detailExperienceYearsMin: number | null
    detailJobAddress: string | null
    detailJobCity: string | null
    detailJobState: string | null
    detailJobCountry: string | null
    detailSeniorityLevel: string | null
    detailLocations: string[] | null
    detailSalary: { display: string } | null
    detailLocationPoints: Array<{ lat: number; lng: number }> | null
}

function jobDetailFetchPendingState(): JobDetailHydrationState {
    return {
        desc: null,
        detailSummary: null,
        detailCompanyDesc: null,
        detailVisaSponsorship: null,
        apiKeywords: [],
        loadingDesc: true,
        detailExperienceYearsMin: null,
        detailJobAddress: null,
        detailJobCity: null,
        detailJobState: null,
        detailJobCountry: null,
        detailSeniorityLevel: null,
        detailLocations: null,
        detailSalary: null,
        detailLocationPoints: null,
    }
}

function jobDetailStateFromCacheEntry(
    c: JobDetailCacheEntry
): JobDetailHydrationState {
    return {
        desc: c.desc,
        detailSummary: c.detailSummary,
        detailCompanyDesc: c.detailCompanyDesc,
        detailVisaSponsorship: c.detailVisaSponsorship,
        apiKeywords: Array.isArray(c.apiKeywords) ? c.apiKeywords : [],
        loadingDesc: false,
        detailExperienceYearsMin: c.detailExperienceYearsMin ?? null,
        detailJobAddress: c.detailJobAddress ?? null,
        detailJobCity: c.detailJobCity ?? null,
        detailJobState: c.detailJobState ?? null,
        detailJobCountry: c.detailJobCountry ?? null,
        detailSeniorityLevel: c.detailSeniorityLevel ?? null,
        detailLocations: Array.isArray(c.detailLocations)
            ? c.detailLocations
            : null,
        detailSalary: c.detailSalary ?? null,
        detailLocationPoints: Array.isArray(c.detailLocationPoints)
            ? c.detailLocationPoints
            : null,
    }
}

/* No cache and fetch not allowed yet (swipe preview) — avoid perpetual loadingDesc. */
function jobDetailDeferredState(): JobDetailHydrationState {
    return {
        desc: null,
        detailSummary: null,
        detailCompanyDesc: null,
        detailVisaSponsorship: null,
        apiKeywords: [],
        loadingDesc: false,
        detailExperienceYearsMin: null,
        detailJobAddress: null,
        detailJobCity: null,
        detailJobState: null,
        detailJobCountry: null,
        detailSeniorityLevel: null,
        detailLocations: null,
        detailSalary: null,
        detailLocationPoints: null,
    }
}

function jobDetailInitialState(
    jobId: string,
    jobsApiUrl: string,
    fetchEnabled: boolean
): JobDetailHydrationState {
    const c = readJobDetailCache(jobId, jobsApiUrl)
    if (c) return jobDetailStateFromCacheEntry(c)
    if (!fetchEnabled) return jobDetailDeferredState()
    return jobDetailFetchPendingState()
}



function jobTimeAgo(iso: string | null): string {
    if (!iso) return ""
    const s = Math.floor((Date.now() - new Date(iso).getTime()) / 1000)
    if (s < 60) return "just now"
    const m = Math.floor(s / 60)
    if (m < 60) return `${m}m ago`
    const h = Math.floor(m / 60)
    if (h < 24) return `${h}h ago`
    const d = Math.floor(h / 24)
    return `${d}d ago`
}

function jobSnippetToHomepageJob(job: JobSnippet): HomepageJob {
    return {
        id: job.id,
        title: job.title,
        company: {
            name: job.company,
            logo_url: job.company_logo ?? null,
            description: null,
            website_url: null,
            linkedin_url: null,
            x_url: null,
            instagram_url: null,
            tiktok_url: null,
            github_url: null,
            youtube_url: null,
            glassdoor_url: null,
            crunchbase_url: null,
            huggingface_url: null,
            facebook_url: null,
        },
        posted_at: job.posted_at ?? null,
        apply_url: job.apply_url ?? "",
        locations: job.locations ?? null,
        employment_type: job.employment_type ?? null,
        workplace_type: job.workplace_type ?? null,
        salary: null,
        job_summary: job.summary ?? null,
        seniority_level: job.seniority_level ?? null,
    }
}

/** Job cards rendered inside the chat bubble after a search_jobs tool call */
const ChatJobCards = React.memo(function ChatJobCards({
    jobs,
    onJobClick,
    themeColors = darkColors,
}: {
    jobs: JobSnippet[]
    onJobClick?: (job: JobSnippet) => void
    themeColors?: typeof darkColors
}) {
    if (!jobs || jobs.length === 0) return null

    const metaStyle: React.CSSProperties = {
        color: themeColors.text.secondary,
        fontSize: 12,
        fontFamily: "Inter",
        fontWeight: 400,
        lineHeight: "18px",
        whiteSpace: "nowrap",
    }

    return (
        <div
            data-layer="jobs"
            style={{
                alignSelf: "stretch",
                flexDirection: "column",
                justifyContent: "flex-start",
                alignItems: "flex-start",
                gap: 10,
                display: "flex",
                width: "100%",
                marginTop: 12,
                marginBottom: 4,
            }}
        >
            {jobs.map((job, i) => (
                <div
                    key={job.id || i}
                    style={{
                        alignSelf: "stretch",
                        paddingLeft: 20,
                        paddingRight: 20,
                        paddingTop: 16,
                        paddingBottom: 16,
                        background: themeColors.surfaceHighlight,
                        overflow: "hidden",
                        borderRadius: 28,
                        flexDirection: "column",
                        justifyContent: "center",
                        alignItems: "flex-start",
                        gap: 8,
                        display: "flex",
                        cursor: "pointer",
                        transition: "opacity 0.15s ease",
                    }}
                    onClick={() => onJobClick?.(job)}
                    onMouseEnter={(e) => {
                        ;(e.currentTarget as HTMLDivElement).style.opacity =
                            "0.75"
                    }}
                    onMouseLeave={(e) => {
                        ;(e.currentTarget as HTMLDivElement).style.opacity = "1"
                    }}
                >
                    <div
                        style={{
                            color: themeColors.text.primary,
                            fontSize: 16,
                            fontFamily: "Inter",
                            fontWeight: 500,
                            lineHeight: "24px",
                            wordBreak: "break-word",
                        }}
                    >
                        {job.title}
                    </div>
                    <div
                        style={{
                            justifyContent: "flex-start",
                            alignItems: "center",
                            gap: 6,
                            display: "flex",
                            flexWrap: "wrap",
                        }}
                    >
                        {/** Logo */}
                        <div
                            style={{
                                width: 16,
                                height: 16,
                                borderRadius: "50%",
                                overflow: "hidden",
                                flexShrink: 0,
                                background: themeColors.surface,
                                display: "flex",
                                alignItems: "center",
                                justifyContent: "center",
                            }}
                        >
                            {job.company_logo && (
                                <img
                                    style={{
                                        width: "100%",
                                        height: "100%",
                                        objectFit: "contain",
                                    }}
                                    src={job.company_logo}
                                    alt=""
                                    onError={(e) => {
                                        ;(
                                            e.currentTarget as HTMLImageElement
                                        ).style.display = "none"
                                    }}
                                />
                            )}
                        </div>
                        {/** Company */}
                        <span style={metaStyle}>{job.company}</span>
                        {/** Date — before location */}
                        {job.posted_at && (
                            <>
                                <span style={metaStyle}>•</span>
                                <span style={metaStyle}>
                                    {jobTimeAgo(job.posted_at)}
                                </span>
                            </>
                        )}
                        {/** Location */}
                        {job.locations?.[0] && (
                            <>
                                <span style={metaStyle}>•</span>
                                <span style={metaStyle}>
                                    {job.locations[0]}
                                </span>
                            </>
                        )}
                        {/** Salary */}
                        {job.salary && (
                            <>
                                <span style={metaStyle}>•</span>
                                <span style={metaStyle}>{job.salary}</span>
                            </>
                        )}
                        {/** Visa sponsorship — only shown when explicitly confirmed */}
                        {job.visa_sponsorship === "yes" && (
                            <>
                                <span style={metaStyle}>•</span>
                                <span style={metaStyle}>Sponsors visa</span>
                            </>
                        )}
                    </div>
                </div>
            ))}
        </div>
    )
})

