                                                        nearbyJobCount
                                                const anywhereTotalCount =
                                                    selectedJobs.length -
                                                    (nearbyJobCount ?? 0)
                                                const tt =
                                                    travelTimes[job.id] ?? null
                                                const driveMins =
                                                    tt?.drivingMins ?? null
                                                const walkMins =
                                                    tt?.walkingMins ?? null
                                                const isWalkable =
                                                    walkMins !== null &&
                                                    walkMins <= 30
                                                const timeDisplay = isWalkable
                                                    ? walkMins
                                                    : driveMins
                                                const hasTime =
                                                    timeDisplay !== null

                                                const postedMs = job.posted_at
                                                    ? Date.now() -
                                                      new Date(
                                                          job.posted_at
                                                      ).getTime()
                                                    : null
                                                const postedStr =
                                                    postedMs === null
                                                        ? null
                                                        : postedMs < 3600000
                                                          ? `${Math.floor(postedMs / 60000)} min ago`
                                                          : postedMs < 86400000
                                                            ? `${Math.floor(postedMs / 3600000)}h ago`
                                                            : `${Math.floor(postedMs / 86400000)}d ago`

