const RoleSelectionButton = React.memo(
    ({
        type,
        isCompact,
        isMobileLayout,
        colors,
    }: {
        type: "student" | "volunteer"
        isCompact: boolean
        isMobileLayout: boolean
        colors: typeof darkColors
    }) => {
        const isStudent = type === "student"
        const label = isStudent ? "Call a mentor" : "Volunteer"
        const desc = isStudent
            ? "Free college and career advice"
            : "Offer free support to students"
        
        const textColor = isStudent
            ? darkColors.text.primary
            : colors.text.primary

        if (isCompact) {
            return (
                <div
                    style={{
                        display: "flex",
                        alignItems: "center",
                        justifyContent: "center",
                        height: "100%",
                        width: "100%",
                        background: isStudent
                            ? colors.semantic.accent
                            : undefined, 
                        color: textColor,
                        fontSize: 15,
                        fontWeight: 600,
                        textAlign: "center",
                        padding: 8,
                    }}
                >
                    {label}
                </div>
            )
        }

        return (
            <div
                style={{
                    padding: isMobileLayout ? 48 : 96,
                    display: "flex",
                    flexDirection: "column",
                    gap: 24,
                    height: "100%",
                }}
            >
                <div
                    style={{
                        color: textColor,
                        fontSize: "24px",
                        fontWeight: "600",
                        lineHeight: "1.2",
                    }}
                >
                    {label}
                </div>
                <div
                    style={{
                        color: textColor,
                        fontSize: "15px",
                        fontWeight: "400",
                        lineHeight: "1.4",
                        opacity: 0.9,
                    }}
                >
                    {desc}
                </div>
            </div>
        )
    }
)

/** OmegleMentorshipUI Main component handling video streaming, real-time signaling, and AI-assisted chat */


const blobToBase64 = (blob: Blob): Promise<string> => {
    return new Promise((resolve, reject) => {
        const reader = new FileReader()
        reader.onload = () => {
            const res = reader.result as string
            resolve(res.substring(res.indexOf(",") + 1))
        }
        reader.onerror = reject
        reader.readAsDataURL(blob)
    })
}

const captureVideoFrame = async (
    streamOrTrack: MediaStream | MediaStreamTrack | null
): Promise<Blob | null> => {
    if (!streamOrTrack) return null
    try {
        const track =
            "getVideoTracks" in streamOrTrack
                ? streamOrTrack.getVideoTracks()[0]
                : streamOrTrack
        if (!track || track.kind !== "video") return null

        
        if ("ImageCapture" in window) {
            try {
                const imageCapture = new (window as any).ImageCapture(track)
                const bitmap = await imageCapture.grabFrame()

                
                const canvas = document.createElement("canvas")
                const scale = Math.min(1, 383 / bitmap.width)
                canvas.width = bitmap.width * scale
                canvas.height = bitmap.height * scale

                const ctx = canvas.getContext("2d")
                if (!ctx) {
                    bitmap.close()
                    return null
                }

                ctx.drawImage(bitmap, 0, 0, canvas.width, canvas.height)
                bitmap.close() 

                return await new Promise<Blob | null>((resolve) =>
                    canvas.toBlob(resolve, "image/jpeg", 0.7)
                )
            } catch (err) {
                console.warn("ImageCapture failed, trying fallback", err)
            }
        }

        
        const video = document.createElement("video")
        video.muted = true
        ;(video as any).playsInline = true
        video.srcObject = new MediaStream([track])
        await video.play()

        const canvas = document.createElement("canvas")
        const scale = Math.min(1, 383 / video.videoWidth)
        canvas.width = video.videoWidth * scale
        canvas.height = video.videoHeight * scale

        const ctx = canvas.getContext("2d")
        if (!ctx) return null

        ctx.drawImage(video, 0, 0, canvas.width, canvas.height)

        
        video.pause()
        video.srcObject = null

        return await new Promise<Blob | null>((resolve) =>
            canvas.toBlob(resolve, "image/jpeg", 0.7)
        )
    } catch (e) {
        return null
    }
}


interface MiniIDEProps {
    code: string
    onChange: (code: string) => void
    mode: "editor" | "player"
    onModeChange: (mode: "editor" | "player") => void
    onClose: () => void
    onDownload: () => void
    isMobileLayout: boolean
    themeColors?: typeof darkColors
    remoteCursors?: Map<string, { x: number; y: number; color: string }>
    onCursorMove?: (x: number, y: number) => void
    onAppInteraction?: (event: any) => void
    remoteAppEvent?: any
    onAppMutation?: (mutation: any) => void
    remoteAppMutation?: any
    amIHost?: boolean
    isResizing?: boolean
    onAppInitialState?: (state: any) => void
    remoteAppInitialState?: any
    onRequestInitialState?: () => void
    /** When true, iframe host/client code mirrors verbose logs to the browser console */
    debugP2P?: boolean
}


const highlightSyntax = (
    code: string,
    themeColors: ThemeColors = darkColors
) => {
    const tokens: React.ReactNode[] = []
    const regex =
        /((?:\/\/.*)|(?:\/\*[\s\S]*?\*\/)|(?:"(?:[^"\\]|\\.)*")|(?:'(?:[^'\\]|\\.)*')|(?:`(?:[^`\\]|\\.)*`)|(?:\b(?:function|const|let|var|return|if|else|for|while|switch|case|break|continue|import|export|from|default|class|interface|type|extends|implements|new|this|super|try|catch|finally|throw|async|await|void|typeof|instanceof|in|of)\b)|(?:\b(?:true|false|null|undefined|NaN|Infinity)\b)|(?:\b\d+(?:\.\d+)?\b)|(?:<[^>]+>))/g

    let lastIndex = 0
    let match

    while ((match = regex.exec(code)) !== null) {
        const [text] = match
        const index = match.index
        if (index > lastIndex) tokens.push(code.slice(lastIndex, index))

        let color = themeColors.text.primary // default
        if (text.startsWith("//") || text.startsWith("/*"))
            color = themeColors.code.comment 
        else if (
            text.startsWith('"') ||
            text.startsWith("'") ||
            text.startsWith("`")
        )
            color = themeColors.code.string 
        else if (/^[0-9]/.test(text))
            color = themeColors.code.number 
        else if (text.startsWith("<"))
            color = themeColors.code.tag 
        else if (/^(true|false|null|undefined)$/.test(text))
            color = themeColors.code.tag 
        else color = themeColors.code.keyword 

        tokens.push(
            <span key={index} style={{ color }}>
                {text}
            </span>
        )
        lastIndex = index + text.length
    }
    if (lastIndex < code.length) tokens.push(code.slice(lastIndex))
    return tokens
}

export interface MiniIDEHandle {
    applyMutation: (mutation: any) => void
    replayInteraction: (interaction: any) => void
    requestInitialState: () => void
}

const MiniIDE = React.memo(
    React.forwardRef<MiniIDEHandle, MiniIDEProps>(function MiniIDE(
        {
            code,
            onChange,
            mode,
            onModeChange,
            onClose,
            onDownload,
            isMobileLayout,
            themeColors = darkColors,
            remoteCursors,
            onCursorMove,
            onAppInteraction,
            remoteAppEvent,
            onAppMutation,
            remoteAppMutation, 
            amIHost,
            isResizing,
            onAppInitialState,
            remoteAppInitialState,
            onRequestInitialState,
            debugP2P = false,
        },
        ref
    ) {
        const iframeRef = React.useRef<HTMLIFrameElement>(null)

        
        React.useImperativeHandle(ref, () => ({
            applyMutation: (mutation: any) => {
                if (iframeRef.current && iframeRef.current.contentWindow) {
                    iframeRef.current.contentWindow.postMessage(
                        {
                            type: "apply-mutation",
                            mutation: mutation,
                        },
                        "*"
                    )
                }
            },
            replayInteraction: (interaction: any) => {
                if (iframeRef.current && iframeRef.current.contentWindow) {
                    iframeRef.current.contentWindow.postMessage(
                        {
                            ...interaction,
                            type: "replay-interaction",
                        },
                        "*"
                    )
                }
            },
            requestInitialState: () => {
                if (iframeRef.current && iframeRef.current.contentWindow) {
                    iframeRef.current.contentWindow.postMessage(
                        {
                            type: "request-initial-state",
                        },
                        "*"
                    )
                }
            },
        }))

        const containerRef = React.useRef<HTMLDivElement>(null)
        const textareaRef = React.useRef<HTMLTextAreaElement>(null)
        const [isDownloadHovered, setIsDownloadHovered] = React.useState(false)
        const [isCloseHovered, setIsCloseHovered] = React.useState(false)
        const [isPlayButtonHovered, setIsPlayButtonHovered] =
            React.useState(false)
        const [isCodeButtonHovered, setIsCodeButtonHovered] =
            React.useState(false)

        
        const lineNumbers = React.useMemo(() => {
            const lines = code.split("\n").length
            return Array.from({ length: lines }, (_, i) => i + 1).join("\n")
        }, [code])

        const handlePointerMove = React.useCallback(
            (e: React.PointerEvent) => {
                if (!onCursorMove || !containerRef.current) return

                const rect = containerRef.current.getBoundingClientRect()
                const x = (e.clientX - rect.left) / rect.width
                const y = (e.clientY - rect.top) / rect.height

                if (x >= 0 && x <= 1 && y >= 0 && y <= 1) {
                    onCursorMove(x, y)
                }
            },
            [onCursorMove]
        )

        
        React.useLayoutEffect(() => {
            if (textareaRef.current) {
                textareaRef.current.style.height = "auto"
                textareaRef.current.style.height =
                    textareaRef.current.scrollHeight + "px"
            }
        }, [code, mode])

        const isPlayable = code.trim().length > 0

        const editorStyles: React.CSSProperties = {
            fontFamily: '"Google Sans Code", monospace',
            fontSize: isMobileLayout ? 16 : 15,
            lineHeight: "24px",
            whiteSpace: "pre",
            padding: "20px",
            paddingBottom: "80px",
            margin: 0,
            border: "none",
            outline: "none",
            width: "100%",
            height: "100%",
            boxSizing: "border-box",
            tabSize: 4,
            overflow: "hidden", 
        }

        

        
        React.useEffect(() => {
            if (mode !== "player") return

            const handleMessage = (e: MessageEvent) => {
                
                
                
                try {
                    if (!e.data || typeof e.data !== "object") return
                    if (e.data.type === "iframe-cursor-move") {
                        if (onCursorMove) {
                            onCursorMove(e.data.x, e.data.y)
                        }
                    } else if (e.data.type === "iframe-interaction") {
                        if (onAppInteraction) {
                            onAppInteraction(e.data)
                        }
                    } else if (e.data.type === "iframe-mutation") {
                        if (onAppMutation) {
                            onAppMutation(e.data.payload)
                        }
                    } else if (e.data.type === "iframe-initial-state") {
                        if (onAppInitialState) {
                            onAppInitialState(e.data.payload)
                        }
                    } else if (e.data.type === "request-initial-state") {
                        if (onRequestInitialState) {
                            onRequestInitialState()
                        }
                    }
                    
                } catch (e) {
                    console.error(
                        "[App Player] Error handling iframe message:",
                        e
                    )
                }
            }

            window.addEventListener("message", handleMessage)
            return () => window.removeEventListener("message", handleMessage)
        }, [
            mode,
            onCursorMove,
            onAppInteraction,
            onAppMutation,
            onAppInitialState,
            onRequestInitialState,
            debugP2P,
        ])

        
        React.useEffect(() => {
            if (
                remoteAppEvent &&
                iframeRef.current &&
                iframeRef.current.contentWindow
            ) {
                iframeRef.current.contentWindow.postMessage(
                    {
                        ...remoteAppEvent,
                        type: "replay-interaction",
                    },
                    "*"
                )
            }
        }, [remoteAppEvent])

        React.useEffect(() => {
            if (
                remoteAppInitialState &&
                !amIHost &&
                iframeRef.current &&
                iframeRef.current.contentWindow
            ) {
                iframeRef.current.contentWindow.postMessage(
                    {
                        type: "apply-initial-state",
                        payload: remoteAppInitialState,
                    },
                    "*"
                )
            }
        }, [remoteAppInitialState, amIHost, debugP2P])

        React.useEffect(() => {
            if (
                remoteAppMutation &&
                !amIHost &&
                iframeRef.current &&
                iframeRef.current.contentWindow
            ) {
                iframeRef.current.contentWindow.postMessage(
                    {
                        type: "apply-mutation",
                        mutation: remoteAppMutation,
                    },
                    "*"
                )
            }
        }, [remoteAppMutation, amIHost])

        return (
            <div
                ref={containerRef}
                onPointerMove={handlePointerMove}
                onPointerLeave={() => {
                    if (onCursorMove) {
                        onCursorMove(-9999, -9999)
                    }
                }}
                data-layer="code editor and app player"
                className="CodeEditorAndAppPlayer"
                style={{
                    width: "100%",
                    height: "100%",
                    paddingTop: 0,
                    background: themeColors.backgroundDark,
                    overflow: "hidden",
                    borderRadius: isMobileLayout ? 0 : "28px 0 0 28px",
                    flexDirection: "column",
                    justifyContent: "flex-start",
                    alignItems: "stretch",
                    gap: 0,
                    display: "flex",
                    position: "relative",
                }}
            >
                {/** Scrollable Content Area */}
                <div
                    data-layer="text area"
                    className="TextArea"
                    {...(isMobileLayout ? { "data-pull-scroll": "1" } : {})}
                    style={{
                        width: "100%",
                        height: "100%",
                        display: mode === "editor" ? "flex" : "none",
                        position: "absolute", 
                        top: 0,
                        left: 0,
                        overflow: "auto",
                        background: themeColors.backgroundDark,
                        alignItems: "stretch",
                        zIndex: 0, 
                    }}
                >
                    {/** Line Numbers Container */}
                    <div
                        data-layer="line numbers toolbar"
                        className="LineNumbersToolbar"
                        style={{
                            position: "sticky",
                            left: 0,
                            zIndex: 20,
                            height: "min-content",
                            minHeight: "100%",
                            flexShrink: 0,
                            background: themeColors.backgroundDark,
                            paddingTop: 80, 
                            paddingBottom: 80,
                            paddingLeft: 12,
                            paddingRight: 12,
                            userSelect: "none",
                        }}
                    >
                        <div
                            style={{
                                textAlign: "right",
                                color: themeColors.text.tertiary,
                                fontSize: isMobileLayout ? 16 : 15,
                                fontFamily: '"Google Sans Code", monospace',
                                lineHeight: "24px",
                                whiteSpace: "pre",
                            }}
                        >
                            {lineNumbers}
                        </div>
                    </div>

                    {/** Code Editor Container */}
                    <div
                        data-layer="code content"
                        className="CodeContent"
                        style={{
                            flex: "1",
                            minHeight: "100%",
                            position: "relative",
                            minWidth: 0, 
                            display: "flex", 
                            flexDirection: "column",
                        }}
                    >
                        {/** Wrapper for content to allow horizontal expansion */}
                        <div
                            style={{
                                position: "relative",
                                minWidth: "100%",
                                width: "fit-content", 
                                minHeight: "100%",
                                flex: 1,
                            }}
                        >
                            {/** Syntax Highlight Layer */}
                            <pre
                                aria-hidden="true"
                                style={{
                                    ...editorStyles,
                                    paddingTop: "80px", 
                                    position: "relative", 
                                    top: 0,
                                    left: 0,
                                    pointerEvents: "none",
                                    color: themeColors.text.primary,
                                    overflow: "hidden",
                                    zIndex: 1,
                                    minHeight: "100%",
                                    height: "max-content",
                                    width: "100%",
                                }}
                            >
                                {(() => {
                                    try {
                                        return highlightSyntax(
                                            code,
                                            themeColors
                                        )
                                    } catch {
                                        
                                        return code
                                    }
                                })()}
                            </pre>

                            {/** Input Layer */}
                            <textarea
                                ref={textareaRef}
                                className="UseFontGoogleSansCode"
                                value={code}
                                onChange={(e) => {
                                    
                                    onChange(e.target.value)
                                }}
                                spellCheck={false}
                                autoCapitalize="off"
                                autoComplete="off"
                                autoCorrect="off"
                                style={{
                                    ...editorStyles,
                                    paddingTop: "80px", 
                                    position: "absolute",
                                    top: 0,
                                    left: 0,
                                    color: "transparent",
                                    caretColor: themeColors.text.primary,
                                    background: "transparent",
                                    resize: "none",
                                    zIndex: 2,
                                    overflow: "hidden",
                                    minHeight: "100%",
                                    width: "100%",
                                    height: "100%",
                                }}
                            />
                        </div>
                    </div>
                </div>

                {/** Mini IDE Toolbar */}
                <div
                    data-layer="toolbar"
                    className="Toolbar"
                    style={{
                        position: "absolute",
                        top: 12,
                        left: 12,
                        right: 12,
                        zIndex: 30,
                        pointerEvents: "none",
                        height: 40,
                        maxWidth: 1800,
                        paddingLeft: 0,
                        paddingRight: 0,
                        justifyContent: "space-between",
                        alignItems: "flex-start",
                        display: "inline-flex",
                    }}
                >
                    <div
                        data-layer="left toolbar"
                        className="LeftToolbar"
                        style={{
                            width: 40,
                            height: 40,
                            paddingLeft: 4,
                            paddingRight: 4,
                            background: themeColors.surface,
                            borderRadius: 28,
                            justifyContent: "center",
                            alignItems: "center",
                            display: "flex",
                            flexWrap: "wrap",
                            alignContent: "center",
                            pointerEvents: "auto",
                        }}
                    >
                        {mode === "player" ? (
                            <div
                                data-svg-wrapper
                                data-layer="open code editor button."
                                className="OpenCodeEditorButton"
                                onClick={() => {
                                    haptic.light()
                                    setIsCodeButtonHovered(false)
                                    onModeChange("editor")
                                }}
                                onMouseEnter={() =>
                                    setIsCodeButtonHovered(true)
                                }
                                onMouseLeave={() =>
                                    setIsCodeButtonHovered(false)
                                }
                                style={{
                                    cursor: "pointer",
                                    position: "relative",
                                }}
                            >
                                {isCodeButtonHovered && (
                                    <Tooltip
                                        style={{
                                            top: "100%",
                                            left: "50%",
                                            transform: "translate(-50%, 8px)",
                                        }}
                                    >
                                        Code
                                    </Tooltip>
                                )}
                                <svg
                                    width="36"
                                    height="36"
                                    viewBox="0 0 40 40"
                                    fill="none"
                                    xmlns="http://www.w3.org/2000/svg"
                                >
                                    <path
                                        d="M25.093 15.974L25.323 16.204C27.112 17.994 28.007 18.888 28.007 20C28.007 21.112 27.112 22.007 25.323 23.796L25.093 24.026M21.879 13L18.128 27M14.913 15.974L14.683 16.204C12.895 17.994 12 18.888 12 20C12 21.112 12.895 22.007 14.685 23.796L14.915 24.026"
                                        stroke={themeColors.text.primary}
                                        stroke-opacity="0.95"
                                        stroke-width="1.2"
                                        stroke-linecap="round"
                                        stroke-linejoin="round"
                                    />
                                </svg>
                            </div>
                        ) : (
                            <div
                                data-svg-wrapper
                                data-layer="play button. opens the working app. (50% greyed out when IDE is already open)"
                                className="PlayButtonOpensTheWorkingApp50GreyedOutWhenIdeIsAlreadyOpen"
                                onClick={() => {
                                    setIsPlayButtonHovered(false)
                                    if (!isPlayable) return
                                    haptic.light()
                                    onModeChange("player")
                                }}
                                onMouseEnter={() =>
                                    setIsPlayButtonHovered(true)
                                }
                                onMouseLeave={() =>
                                    setIsPlayButtonHovered(false)
                                }
                                style={{
                                    cursor: isPlayable ? "pointer" : "default",
                                    opacity: isPlayable ? 1 : 0.5,
                                    position: "relative",
                                }}
                            >
                                {isPlayButtonHovered && (
                                    <Tooltip
                                        style={{
                                            top: "100%",
                                            left: "50%",
                                            transform: "translate(-50%, 8px)",
                                        }}
                                    >
                                        Preview
                                    </Tooltip>
                                )}
                                <svg
                                    width="36"
                                    height="36"
                                    viewBox="0 0 40 40"
                                    fill="none"
                                    xmlns="http://www.w3.org/2000/svg"
                                >
                                    <path
                                        d="M25.1692 20C25.1692 20.7614 18.9674 24.5629 16.2377 25.9728C15.4682 26.3702 14.9347 26.0432 14.903 25.1777C14.8118 22.6836 14.8146 17.3166 14.9054 14.8224C14.9369 13.957 15.4717 13.6195 16.2432 14.013C18.9845 15.4113 25.1692 19.236 25.1692 20Z"
                                        stroke={themeColors.text.primary}
                                        stroke-opacity="0.95"
                                        stroke-width="1.2"
                                        stroke-linecap="round"
                                        stroke-linejoin="round"
                                    />
                                </svg>
                            </div>
                        )}
                    </div>
                    <HeaderActions
                        themeColors={themeColors}
                        onDownloadClick={onDownload}
                        onCloseClick={onClose}
                        isDownloadHovered={isDownloadHovered}
                        onDownloadHoverChange={setIsDownloadHovered}
                        isCloseHovered={isCloseHovered}
                        onCloseHoverChange={setIsCloseHovered}
                    />
                </div>

                {/** App Player (iframe) */}
                {mode === "player" && (
                    <div
                        {...(isMobileLayout ? { "data-pull-scroll": "1" } : {})}
                        style={{
                            alignSelf: "stretch",
                            flex: "1 1 0",
                            width: "100%",
                            height: "100%",
                            background: themeColors.backgroundDark,
                            position: "relative",
                            boxSizing: "border-box",
                            pointerEvents: isResizing ? "none" : "auto",
                        }}
                    >
                        <div
                            style={{
                                width: "100%",
                                height: "100%",
                                background: themeColors.backgroundDark,
                            }}
                        >
                            <iframe
                                ref={iframeRef}
                                srcDoc={(() => {
                                    
                                    
                                    try {
                                        
                                        const hostScript = `<script>
                                    // Utility to generate a selector for an element
                                    function getSelector(el) {
                                        if (!el) return null;
                                        if (el.nodeType === 3) return getSelector(el.parentNode); // Handle text nodes
                                        if (el.tagName.toLowerCase() === 'html') return 'html';
                                        if (el.tagName.toLowerCase() === 'body') return 'body';
                                        if (el.id) return '#' + el.id;
                                        
                                        let selector = el.tagName.toLowerCase();
                                        if (el.className && typeof el.className === 'string') {
                                            const classes = el.className.trim().split(/\s+/).filter(c => c);
                                            if (classes.length > 0) {
                                                selector += '.' + classes.join('.');
                                            }
                                        }
                                        
                                        let sibling = el;
                                        let nth = 1;
                                        while (sibling = sibling.previousElementSibling) {
                                            if (sibling.tagName.toLowerCase() == el.tagName.toLowerCase())
                                                nth++;
                                        }
                                        if (nth > 1) selector += ':nth-of-type(' + nth + ')';
                                        
                                        return selector;
                                    }

                                    // Listen for interactions
                                    document.addEventListener('mousemove', (e) => {
                                        const x = e.clientX / window.innerWidth;
                                        const y = e.clientY / window.innerHeight;
                                        window.parent.postMessage({ type: 'iframe-cursor-move', x, y }, '*');
                                    });
                                    document.addEventListener('mouseleave', () => {
                                         window.parent.postMessage({ type: 'iframe-cursor-move', x: -9999, y: -9999 }, '*');
                                    });

                                    // HOST: Capture Interactions (Replay logic is below)
                                    // Note: Host doesn't need to capture its own interactions to send to itself, 
                                    // For now, Host just runs natively.

                                    // HOST: Mutation Observer
                                    const observer = new MutationObserver((mutations) => {
                                        mutations.forEach((mutation) => {
                                            // DEBUG: Log mutation (commented out for performance)

                                            // Filter out non-element nodes for simplicity if needed, 
                                            // but text nodes are important for characterData
                                            
                                            let payload = {
                                                type: mutation.type,
                                                selector: getSelector(mutation.target)
                                            };

                                            if (mutation.type === 'characterData') {
                                                payload.value = mutation.target.textContent;
                                                // Ensure selector points to the parent element for text nodes
                                                if (mutation.target.nodeType === 3) {
                                                     payload.selector = getSelector(mutation.target.parentNode);
                                                     // For text nodes, we often just want to update the parent's text content or innerHTML
                                                     // But characterData is specific. 
                                                     // Simplification: Treat characterData on text node as childList update on parent
                                                     // to ensure robust sync (re-rendering the text node).
                                                     payload.type = 'childList';
                                                     payload.value = mutation.target.parentNode.innerHTML;
                                                }
                                            } else if (mutation.type === 'attributes') {
                                                payload.attributeName = mutation.attributeName;
                                                payload.value = mutation.target.getAttribute(mutation.attributeName);
                                            } else if (mutation.type === 'childList') {
                                                // For simplicity in this lightweight implementation,
                                                // we send the full innerHTML of the parent when children change.
                                                if (mutation.target.nodeType === 1) { // ELEMENT_NODE
                                                     payload.value = mutation.target.innerHTML;
                                                } else {
                                                     // If target is text node, use parent
                                                     payload.selector = getSelector(mutation.target.parentNode);
                                                     payload.value = mutation.target.parentNode.innerHTML;
                                                }
                                            }
                                            
                                            window.parent.postMessage({
                                                type: 'iframe-mutation',
                                                payload: payload
                                            }, '*');
                                        });
                                    });
                                    
                                    observer.observe(document.documentElement, {
                                        attributes: true,
                                        childList: true,
                                        subtree: true,
                                        characterData: true
                                    });

                                    // Send initial state when DOM is ready
                                    let initialStateSent = false;
                                    function sendInitialState() {
                                        if (initialStateSent) return;
                                        
                                        try {
                                            const bodyHTML = document.body.innerHTML;
                                            const boardEl = document.getElementById('board');
                                            const boardHTML = boardEl ? boardEl.innerHTML : null;
                                            
                                            // Only send if body has content and board exists with children
                                            if (bodyHTML && bodyHTML.trim().length > 0) {
                                                const state = {
                                                    bodyHTML: bodyHTML,
                                                    boardHTML: boardHTML
                                                };
                                                
                                                // Verify board has children if it exists
                                                if (!boardEl || (boardEl && boardEl.children.length > 0)) {
                                                    window.parent.postMessage({
                                                        type: 'iframe-initial-state',
                                                        payload: state
                                                    }, '*');
                                                    initialStateSent = true;
                                                }
                                            }
                                        } catch (e) {
                                        }
                                    }
                                    
                                    // Try sending initial state multiple times
                                    if (document.readyState === 'complete') {
                                        sendInitialState();
                                    } else {
                                        window.addEventListener('load', sendInitialState);
                                    }
                                    
                                    setTimeout(() => {
                                        sendInitialState();
                                    }, 500);
                                    
                                    setTimeout(() => {
                                        sendInitialState();
                                    }, 1500);
                                    
                                    // Listen for initial state requests from clients
                                    window.addEventListener('message', (e) => {
                                        if (e.data && e.data.type === 'request-initial-state') {
                                            sendInitialState();
                                        }
                                    });

                                    // Listen for replay events (from Client)
                                    window.addEventListener('message', (e) => {
                                        if (e.data && e.data.type === 'replay-interaction') {
                                            const { kind, id, x, y, value, checked, scrollTop, scrollLeft } = e.data;
                                            
                                            //                                             // if (debugMode) console.log('[Host Script] Replaying:', kind, id, x, y);

                                            // FIND ELEMENT: 1. ID, 2. Coordinates (Click), 3. Selector (Legacy/Scroll)
                                            let el = null;
                                            
                                            if (id) el = document.getElementById(id);
                                            
                                            // 2. Fallback to Coordinates (Best for clicks without ID)
                                            if (!el && kind === 'click' && x !== undefined && y !== undefined) {
                                                const clientX = x * window.innerWidth;
                                                const clientY = y * window.innerHeight;
                                                el = document.elementFromPoint(clientX, clientY);
                                            }
                                            
                                            // 3. Fallback to Selector (Legacy or Scroll/Input without ID)
                                            if (!el && e.data.selector) {
                                                if (e.data.selector === 'html') el = document.documentElement;
                                                else if (e.data.selector === 'body') el = document.body;
                                                else el = document.querySelector(e.data.selector);
                                            }
                                            
                                            if (!el) return;

                                            if (kind === 'click') {
                                                // if (debugMode) console.log('[Host Script] Clicking element:', el);
                                                // Prefer native .click() to trigger inline handlers reliably
                                                if (typeof el.click === 'function') {
                                                    el.click();
                                                } else {
                                                    const clientX = (x || 0.5) * window.innerWidth;
                                                    const clientY = (y || 0.5) * window.innerHeight;
                                                    const opts = {
                                                        view: window,
                                                        bubbles: true,
                                                        cancelable: true,
                                                        clientX: clientX,
                                                        clientY: clientY
                                                    };
                                                    el.dispatchEvent(new MouseEvent('click', opts));
                                                    el.dispatchEvent(new MouseEvent('mousedown', opts));
                                                    el.dispatchEvent(new MouseEvent('mouseup', opts));
                                                }
                                                
                                                // Focus inputs
                                                if (el.tagName === 'INPUT' || el.tagName === 'TEXTAREA' || el.tagName === 'SELECT') {
                                                    el.focus();
                                                }
                                            } else if (kind === 'input') {
                                                el.value = value;
                                                if (checked !== undefined) el.checked = checked;
                                                el.dispatchEvent(new Event('input', { bubbles: true }));
                                                el.dispatchEvent(new Event('change', { bubbles: true }));
                                            } else if (kind === 'scroll') {
                                                if (e.data.selector === 'html' || e.data.selector === 'body') {
                                                    window.scrollTo(scrollLeft, scrollTop);
                                                } else {
                                                    el.scrollTop = scrollTop;
                                                    el.scrollLeft = scrollLeft;
                                                }
                                            }
                                        }
                                    });
                                </script>`

                                        
                                        const clientScript = `<script>
                                    function getSelector(el) {
                                        if (!el) return null;
                                        if (el.nodeType === 3) return getSelector(el.parentNode);
                                        if (el.tagName.toLowerCase() === 'html') return 'html';
                                        if (el.tagName.toLowerCase() === 'body') return 'body';
                                        if (el.id) return '#' + el.id;
                                        let selector = el.tagName.toLowerCase();
                                        if (el.className && typeof el.className === 'string') {
                                            const classes = el.className.trim().split(/\s+/).filter(c => c);
                                            if (classes.length > 0) selector += '.' + classes.join('.');
                                        }
                                        let sibling = el;
                                        let nth = 1;
                                        while (sibling = sibling.previousElementSibling) {
                                            if (sibling.tagName.toLowerCase() == el.tagName.toLowerCase()) nth++;
                                        }
                                        if (nth > 1) selector += ':nth-of-type(' + nth + ')';
                                        return selector;
                                    }

                                    // Capture Interactions to send to Host
                                    document.addEventListener('mousemove', (e) => {
                                        const x = e.clientX / window.innerWidth;
                                        const y = e.clientY / window.innerHeight;
                                        window.parent.postMessage({ type: 'iframe-cursor-move', x, y }, '*');
                                    });
                                    document.addEventListener('mouseleave', () => {
                                         window.parent.postMessage({ type: 'iframe-cursor-move', x: -9999, y: -9999 }, '*');
                                    });

                                    document.addEventListener('click', (e) => {
                                        if (!e.isTrusted) return;
                                        // Stop local execution of inline handlers on Client to prevent ReferenceErrors
                                        // But allow default behavior for inputs/links if needed, though usually we want to mirror Host.
                                        // So we only stop if it's NOT an input-like element.
                                        const tag = e.target.tagName.toLowerCase();
                                        if (tag !== 'input' && tag !== 'textarea' && tag !== 'select') {
                                            e.preventDefault();
                                            e.stopPropagation();
                                            e.stopImmediatePropagation();
                                        }
                                        
                                        const selector = getSelector(e.target);
                                        
                                        let targetId = e.target.id;
                                        if (!targetId && e.target.parentElement) {
                                            const closest = e.target.closest('[id]');
                                            if (closest) targetId = closest.id;
                                        }

                                        window.parent.postMessage({ 
                                            type: 'iframe-interaction', 
                                            kind: 'click',
                                            id: targetId,
                                            selector: selector,
                                            x: e.clientX / window.innerWidth,
                                            y: e.clientY / window.innerHeight
                                        }, '*');
                                    }, true);

                                    document.addEventListener('input', (e) => {
                                        if (!e.isTrusted) return;
                                        const selector = getSelector(e.target);
                                        window.parent.postMessage({ 
                                            type: 'iframe-interaction', 
                                            kind: 'input',
                                            id: e.target.id,
                                            selector: selector,
                                            value: e.target.value,
                                            checked: e.target.checked
                                        }, '*');
                                    }, true);
                                    
                                    let scrollTimeout;
                                    document.addEventListener('scroll', (e) => {
                                        if (!e.isTrusted) return;
                                        if (scrollTimeout) return;
                                        scrollTimeout = setTimeout(() => {
                                            scrollTimeout = null;
                                            const target = e.target === document ? document.documentElement : e.target;
                                            const selector = e.target === document ? 'html' : getSelector(target);
                                            window.parent.postMessage({
                                                type: 'iframe-interaction',
                                                kind: 'scroll',
                                                selector: selector,
                                                scrollTop: target.scrollTop,
                                                scrollLeft: target.scrollLeft
                                            }, '*');
                                        }, 50);
                                    }, true);

                                    // Request initial state multiple times until received
                                    let initialStateReceived = false;
                                    let requestAttempts = 0;
                                    const maxRequestAttempts = 10;
                                    
                                    function requestInitialState() {
                                        if (initialStateReceived) return;
                                        requestAttempts++;
                                        if (requestAttempts > maxRequestAttempts) {
                                            return;
                                        }
                                        window.parent.postMessage({ type: 'request-initial-state' }, '*');
                                    }
                                    
                                    // Request initial state immediately and on intervals
                                    requestInitialState();
                                    setTimeout(requestInitialState, 300);
                                    setTimeout(requestInitialState, 800);
                                    setTimeout(requestInitialState, 1500);
                                    
                                    window.addEventListener('message', (e) => {
                                        if (e.data && e.data.type === 'apply-initial-state') {
                                            if (initialStateReceived) return;
                                            
                                            const { bodyHTML, boardHTML } = e.data.payload;
                                            if (!bodyHTML || bodyHTML.trim().length === 0) {
                                                setTimeout(requestInitialState, 200);
                                                return;
                                            }
                                            
                                            try {
                                                
                                                document.body.innerHTML = bodyHTML;
                                                
                                                if (boardHTML !== null && boardHTML !== undefined) {
                                                    const boardEl = document.getElementById('board');
                                                    if (boardEl) {
                                                        boardEl.innerHTML = boardHTML;
                                                    } else {
                                                        // Retry board application after delay
                                                        setTimeout(() => {
                                                            const retryBoardEl = document.getElementById('board');
                                                            if (retryBoardEl) {
                                                                retryBoardEl.innerHTML = boardHTML;
                                                            } else {
                                                            }
                                                        }, 200);
                                                    }
                                                }
                                                
                                                initialStateReceived = true;
                                            } catch (err) {
                                                setTimeout(requestInitialState, 500);
                                            }
                                        }
                                    });

                                    window.addEventListener('message', (e) => {
                                        if (e.data && e.data.type === 'apply-mutation') {
                                            const { type, selector, value, attributeName } = e.data.mutation;
                                            
                                            let el;
                                            if (selector === 'html') el = document.documentElement;
                                            else if (selector === 'body') el = document.body;
                                            else if (selector === '#board') el = document.getElementById('board');
                                            else el = document.querySelector(selector);

                                            if (!el) {
                                                // console.warn('[Client] Element not found for selector:', selector);
                                                // Retry with delay, especially for board mutations
                                                const retryDelay = selector === '#board' || selector.includes('board') ? 200 : 50;
                                                setTimeout(() => {
                                                    const retryEl = selector === '#board' ? document.getElementById('board') : document.querySelector(selector);
                                                    if (retryEl) {
                                                        applyMutation(retryEl, type, value, attributeName);
                                                    } else {
                                                    }
                                                }, retryDelay);
                                                return;
                                            }
                                            
                                            applyMutation(el, type, value, attributeName);
                                        }
                                    });

                                    function applyMutation(el, type, value, attributeName) {
                                        if (type === 'characterData') {
                                            el.textContent = value;
                                        } else if (type === 'attributes') {
                                            // Strip event handlers to prevent ReferenceErrors on Client
                                            if (attributeName.startsWith('on')) return;
                                            
                                            if (value === null) el.removeAttribute(attributeName);
                                            else el.setAttribute(attributeName, value);
                                        } else if (type === 'childList') {
                                            // Strip event handlers from innerHTML to prevent ReferenceErrors
                                            const safeValue = value.replace(/\s+on[a-z]+\s*=\s*(?:"[^"]*"|'[^']*'|[^\s>]+)/gi, "");
                                            el.innerHTML = safeValue;
                                        }
                                    }
                                </script>`

                                        
                                        let processedCode = code
                                        if (mode === "player") {
                                            const styles =
                                                code
                                                    .match(
                                                        /<style[^>]*>([\s\S]*?)<\/style>/gi
                                                    )
                                                    ?.join("") || ""
                                            const inlineStyle =
                                                code.match(
                                                    /<body[^>]*style\s*=\s*["']([^"']*)["']/i
                                                )?.[1] || ""
                                            const allStyles =
                                                styles + inlineStyle
                                            const hasAll =
                                                /\bbody\s*\{/i.test(
                                                    allStyles
                                                ) &&
                                                /margin\s*:/i.test(allStyles) &&
                                                /color\s*:/i.test(allStyles) &&
                                                /font-family\s*:/i.test(
                                                    allStyles
                                                )

                                            if (!hasAll) {
                                                const defaultStyle = `<style>body { margin: 86px 24px 0px 24px; color: #ffffff; font-family: sans-serif; }</style>`
                                                if (code.includes("<head>")) {
                                                    processedCode =
                                                        code.replace(
                                                            "<head>",
                                                            `<head>${defaultStyle}`
                                                        )
                                                } else if (
                                                    code.includes("<html>")
                                                ) {
                                                    processedCode =
                                                        code.replace(
                                                            "<html>",
                                                            `<html><head>${defaultStyle}</head>`
                                                        )
                                                } else {
                                                    processedCode = `<html><head>${defaultStyle}</head><body>${code}</body></html>`
                                                }
                                            }
                                        }

                                        if (amIHost) {
                                            
                                            return processedCode.includes(
                                                "<head>"
                                            )
                                                ? processedCode.replace(
                                                      "<head>",
                                                      `<head><base target="_blank">${hostScript}`
                                                  )
                                                : `<base target="_blank">${hostScript}${processedCode}`
                                        } else {
                                            
                                            
                                            
                                            const sanitized = processedCode
                                                .replace(
                                                    /<script\b[^>]*>([\s\S]*?)<\/script>/gim,
                                                    ""
                                                )
                                                .replace(
                                                    /\s+on[a-z]+\s*=\s*(?:"[^"]*"|'[^']*'|[^\s>]+)/gi,
                                                    ""
                                                ) // Remove inline handlers

                                            // If code has no body/head, wrap it
                                            let finalCode = sanitized
                                            if (!finalCode.includes("<body")) {
                                                finalCode = `<body>${finalCode}</body>`
                                            }

                                            return finalCode.includes("<head>")
                                                ? finalCode.replace(
                                                      "<head>",
                                                      `<head><base target="_blank">${clientScript}`
                                                  )
                                                : `<base target="_blank">${clientScript}${finalCode}`
                                        }
                                    } catch (e) {
                                        console.error(
                                            "[App Player] Failed to build srcDoc:",
                                            e
                                        )
                                        return `<!DOCTYPE html><html><body style="background:#141414;color:#fff;font-family:sans-serif;padding:86px 24px 24px;margin:0"><p style="opacity:0.7">⚠️ Could not render app. Open the editor to fix the code.</p></body></html>`
                                    }
                                })()}
                                style={{
                                    width: "100%",
                                    height: "100%",
                                    border: "none",
                                }}
                                title="App Player"
                                sandbox="allow-scripts allow-same-origin allow-forms allow-popups allow-modals"
                            />
                        </div>
                    </div>
                )}

                {/* Remote Cursors */}
                {remoteCursors &&
                    Array.from(remoteCursors.entries()).map(
                        ([peerId, cursor]) => (
                            <LiveCursor
                                key={peerId}
                                x={cursor.x}
                                y={cursor.y}
                                color={cursor.color}
                                containerRef={containerRef}
                                themeColors={themeColors}
                            />
                        )
                    )}
            </div>
        )
    })
)

// Blocks document-level pull-to-refresh / rubber-band (esp. iOS Safari) while Curastem is mounted.
let curastemDocumentOverscrollGuardCount = 0
let curastemDocumentOverscrollStyleEl: HTMLStyleElement | null = null
function mountCurastemDocumentOverscrollGuard(): () => void {
    if (typeof document === "undefined") return () => {}
    curastemDocumentOverscrollGuardCount++
    if (curastemDocumentOverscrollGuardCount === 1) {
        const el = document.createElement("style")
        el.setAttribute("data-curastem-document-overscroll", "1")
        el.textContent =
            "html,body{overscroll-behavior:none!important;overscroll-behavior-y:none!important;overscroll-behavior-x:none!important}"
        document.head.appendChild(el)
        curastemDocumentOverscrollStyleEl = el
    }
    return () => {
        curastemDocumentOverscrollGuardCount = Math.max(
            0,
            curastemDocumentOverscrollGuardCount - 1
        )
        if (
            curastemDocumentOverscrollGuardCount === 0 &&
            curastemDocumentOverscrollStyleEl
        ) {
            curastemDocumentOverscrollStyleEl.remove()
            curastemDocumentOverscrollStyleEl = null
        }
    }
}

// Curastem auth + cross-device sync
// Firebase verifies identity; Cloudflare Worker owns all user data.
// Session token stored in cookie (.curastem.org) + localStorage Bearer fallback.
const FIREBASE_CONFIG = {
    apiKey: "AIzaSyA3LmDjf_uwzNCnvte_sQWul9e515Tnpnc",
    authDomain: "curastem.firebaseapp.com",
    projectId: "curastem",
    storageBucket: "curastem.firebasestorage.app",
    messagingSenderId: "256990056414",
    appId: "1:256990056414:web:658aeb5c85676c83e5d74f",
}

const FIREBASE_SDK_VERSION = "10.14.1"
const SESSION_TOKEN_KEY = "curastem_session_token"
const CURRENT_USER_KEY = "curastem_current_user"
const SAVED_CHAT_HISTORY_KEY = "saved_chat_history"
const GUEST_CHAT_HISTORY_KEY = "curastem_guest_chat_history"
const CURRENT_CHAT_ID_KEY = "current_chat_id"
// uid of the account that created a local chat; used to prevent one account's
// unpushed local chats from being merged into a different account on sign-in.
const CHAT_OWNER_KEY = "_owner_uid"
// Module-level mirror of the currently signed-in uid. Written by the auth
// hook and read by every savedChats persistence path so we don't have to
// thread `uid` through every reducer and callback. Null when signed out.
let currentOwnerUid: string | null = null

function readStoredChats(key: string): ChatSession[] {
    if (typeof window === "undefined") return []
    try {
        const raw = localStorage.getItem(key)
        if (!raw) return []
        const parsed = JSON.parse(raw)
        return Array.isArray(parsed) ? (parsed as ChatSession[]) : []
    } catch {
        return []
    }
}

function readGuestChats(): ChatSession[] {
    return readStoredChats(GUEST_CHAT_HISTORY_KEY).filter((c) => {
        const owner = (c as ChatSession & Record<string, unknown>)[CHAT_OWNER_KEY]
        return owner == null || owner === ""
    })
}

function readAccountChats(ownerUid: string | null | undefined): ChatSession[] {
    if (!ownerUid) return []
    return readStoredChats(SAVED_CHAT_HISTORY_KEY).filter((c) => {
        const owner = (c as ChatSession & Record<string, unknown>)[CHAT_OWNER_KEY]
        return owner === ownerUid
    })
}

/**
 * Persist savedChats to localStorage and tag each chat with the current
 * owner uid. This is the ONLY function that should write chat history —
 * funneling through here guarantees two things:
 *   1. Every chat carries `_owner_uid` so cross-account contamination on
 *      the same device is impossible.
 *   2. Signed-in users never lose chats to the legacy 25-chat cap; the cap
 *      only applies when signed out (guest) where quota pressure is real.
 */
function persistSavedChats(chats: ChatSession[]): ChatSession[] {
    if (typeof window === "undefined") return chats
    const uid = currentOwnerUid
    const tagged: ChatSession[] = uid
        ? chats.map((c) =>
              (c as ChatSession & Record<string, unknown>)[CHAT_OWNER_KEY] === uid
                  ? c
                  : ({ ...c, [CHAT_OWNER_KEY]: uid } as ChatSession)
          )
        : chats.filter((c) => {
              const owner = (c as ChatSession & Record<string, unknown>)[CHAT_OWNER_KEY]
              return owner == null || owner === ""
          })
    // Signed-out users hit localStorage quota fast with a few long chats —
    // keep the 25-chat cap for them. Signed-in users have the cloud as the
    // source of truth, and we lazy-load messages, so the cap is harmful.
    const toStore = uid ? tagged : tagged.slice(0, 25)
    const storageKey = uid ? SAVED_CHAT_HISTORY_KEY : GUEST_CHAT_HISTORY_KEY
    try {
        localStorage.setItem(storageKey, JSON.stringify(toStore))
    } catch {
        // QuotaExceeded — fall back to a capped write so we never crash the
        // UI. The cloud still has everything.
        try {
            localStorage.setItem(
                storageKey,
                JSON.stringify(toStore.slice(0, 25))
            )
        } catch {}
    }
    return tagged
}
// All localStorage keys that hold user-generated data and must be cleared on
// sign-out so the next guest (or next account) starts from a clean slate.
const USER_DATA_LS_KEYS = [
    SAVED_CHAT_HISTORY_KEY,
    CURRENT_CHAT_ID_KEY,
    "you_name",
    "you_school",
    "you_work",
    "you_interests",
    "curastem_resume",
    "curastem_resume_doc_html",
    "dismissed_interest_chips",
    "ai_suggestions",
    // Full resume file (base64 data URL + metadata) — must be cleared on sign-out
    // so another account doesn't inherit a prior user's file.
    "curastem_resume_file",
    // Server-side resume metadata stub written by applyMergedSnapshot so the
    // restore-from-R2 effect knows the server has a file even before download.
    "curastem_resume_server_meta",
    RESUME_UPLOAD_PENDING_KEY,
]

type FirebaseUser = {
    uid: string
    email: string | null
    displayName: string | null
    photoURL: string | null
    getIdToken: (forceRefresh?: boolean) => Promise<string>
}

type FirebaseAuth = {
    onAuthStateChanged: (cb: (u: FirebaseUser | null) => void) => () => void
    signInWithPopup: (provider: unknown) => Promise<{ user: FirebaseUser }>
    signInWithRedirect: (provider: unknown) => Promise<void>
    getRedirectResult: () => Promise<{ user: FirebaseUser } | null>
    signOut: () => Promise<void>
    currentUser: FirebaseUser | null
}

type EmailPrefs = {
    job_alerts: boolean
    local_events: boolean
    announcements: boolean
}

type CurastemUser = {
    id: string
    email: string | null
    display_name: string | null
    photo_url: string | null
    email_prefs: EmailPrefs | null
}

type AuthStatus = "loading" | "signed_out" | "signed_in"

interface UseCurastemAuthResult {
    status: AuthStatus
    user: CurastemUser | null
    signInWithGoogle: () => Promise<void>
    signOut: () => Promise<void>
    /** Called automatically right after sign-in; also usable for manual re-sync. */
    syncAll: () => Promise<void>
    /** True while sign-in / sync is running — used to disable the button. */
    busy: boolean
    error: string | null
}

let _firebasePromise: Promise<{ auth: FirebaseAuth; googleProvider: unknown }> | null = null

/**
 * Load Firebase modular SDK from gstatic on demand. Cached across renders so
 * subsequent calls reuse the same Auth instance. Returns null during SSR.
 */
async function loadFirebaseAuth(): Promise<{
    auth: FirebaseAuth
    googleProvider: unknown
} | null> {
    if (typeof window === "undefined") return null
    if (_firebasePromise) return _firebasePromise
    _firebasePromise = (async () => {
        const [{ initializeApp, getApps, getApp }, authMod] = await Promise.all([
            // @ts-ignore — CDN ESM import resolved at runtime, not by Framer's bundler.
            import(
                `https://www.gstatic.com/firebasejs/${FIREBASE_SDK_VERSION}/firebase-app.js`
            ),
            // @ts-ignore
            import(
                `https://www.gstatic.com/firebasejs/${FIREBASE_SDK_VERSION}/firebase-auth.js`
            ),
        ])
        const app = getApps().length ? getApp() : initializeApp(FIREBASE_CONFIG)
        const authInstance = authMod.getAuth(app)
        const provider = new authMod.GoogleAuthProvider()
        provider.setCustomParameters({ prompt: "select_account" })
        const auth: FirebaseAuth = {
            onAuthStateChanged: (cb) =>
                authMod.onAuthStateChanged(authInstance, cb),
            signInWithPopup: (p) => authMod.signInWithPopup(authInstance, p),
            signInWithRedirect: (p) =>
                authMod.signInWithRedirect(authInstance, p),
            getRedirectResult: () => authMod.getRedirectResult(authInstance),
            signOut: () => authMod.signOut(authInstance),
            get currentUser() {
                return authInstance.currentUser
            },
        }
        return { auth, googleProvider: provider }
    })().catch((err) => {
        _firebasePromise = null
        throw err
    })
    return _firebasePromise
}

function useCurastemAuth(apiBase: string): UseCurastemAuthResult {
    const [status, setStatus] = React.useState<AuthStatus>("loading")
    const [user, setUser] = React.useState<CurastemUser | null>(null)
    const [busy, setBusy] = React.useState(false)
    const [error, setError] = React.useState<string | null>(null)

    // Hydrate from existing session (cookie or Bearer) on mount.
    // Also handles ?curastem_token= from the relay-page full-page redirect fallback.
    React.useEffect(() => {
        if (typeof window === "undefined") return
        // If the relay page redirected back with a token in the URL, store it
        // then clean the URL so the token isn't bookmarked or shared.
        try {
            const url = new URL(location.href)
            const relayToken = url.searchParams.get("curastem_token")
            const relayUser = url.searchParams.get("curastem_user")
            if (relayToken) {
                localStorage.setItem(SESSION_TOKEN_KEY, relayToken)
                if (relayUser) {
                    localStorage.setItem(CURRENT_USER_KEY, relayUser)
                }
                url.searchParams.delete("curastem_token")
                url.searchParams.delete("curastem_user")
                history.replaceState(null, "", url.toString())
            }
        } catch {}
        let cancelled = false
        ;(async () => {
            try {
                const me = await appApiFetch(apiBase, APP_API_PATHS.authMe, {
                    method: "GET",
                })
                if (cancelled) return
                if (me.ok) {
                    const data = (await me.json()) as { user: CurastemUser }
                    currentOwnerUid = data.user.id
                    setUser(data.user)
                    setStatus("signed_in")
                    try {
                        localStorage.setItem(
                            CURRENT_USER_KEY,
                            JSON.stringify(data.user)
                        )
                    } catch {}
                } else {
                    currentOwnerUid = null
                    setStatus("signed_out")
                }
            } catch {
                if (!cancelled) {
                    currentOwnerUid = null
                    setStatus("signed_out")
                }
            }
        })()
        return () => {
            cancelled = true
        }
    }, [apiBase])

    // Handle the return leg of signInWithRedirect (popup-blocked fallback).
    // Runs once on mount; no-ops if no redirect was in progress.
    React.useEffect(() => {
        if (typeof window === "undefined") return
        let cancelled = false
        ;(async () => {
            try {
                const fb = await loadFirebaseAuth()
                if (!fb) return
                const result = await fb.auth.getRedirectResult()
                if (!result?.user || cancelled) return
                setBusy(true)
                const idToken = await result.user.getIdToken(true)
                const resp = await fetch(appApiUrl(apiBase, APP_API_PATHS.authFirebase), {
                    method: "POST",
                    credentials: "include",
                    headers: {
                        "Content-Type": "application/json",
                        "X-Curastem-Client": "web",
                    },
                    body: JSON.stringify({ id_token: idToken }),
                })
                if (!resp.ok) throw new Error(`/auth/firebase ${resp.status}`)
                const data = (await resp.json()) as { user: CurastemUser; token: string }
                try {
                    localStorage.setItem(SESSION_TOKEN_KEY, data.token)
                    localStorage.setItem(CURRENT_USER_KEY, JSON.stringify(data.user))
                } catch {}
                currentOwnerUid = data.user.id
                setUser(data.user)
                setStatus("signed_in")
                trackAuthEvent("signin_success", { uid: data.user.id, method: "redirect" })
                try { await syncAll(data.user.id) } catch {}
            } catch (err) {
                console.error("getRedirectResult failed", err)
                trackAuthEvent("signin_failure", {
                    error: (err instanceof Error ? err.message : String(err)).slice(0, 200),
                    method: "redirect",
                })
            } finally {
                if (!cancelled) setBusy(false)
            }
        })()
        return () => { cancelled = true }
    // eslint-disable-next-line react-hooks/exhaustive-deps
    }, [apiBase]) // syncAll intentionally omitted — only runs once

    const syncAll = React.useCallback(
        async (uid: string) => {
            if (typeof window === "undefined") return
            // Only include local chats that were created as a guest (no owner
            // tag) or by the currently signing-in account. This prevents a
            // prior account's unpushed drafts from being merged into a new
            // account after a device switch.
            const snapshot = buildLocalSnapshot({ ownerUid: uid })
            const resp = await appApiFetch(apiBase, APP_API_PATHS.syncPush, {
                method: "POST",
                headers: { "Content-Type": "application/json" },
                body: JSON.stringify(snapshot),
            })
            if (!resp.ok) {
                throw new Error(`sync/push ${resp.status}`)
            }
            const merged = (await resp.json()) as MergedSnapshot
            applyMergedSnapshot(merged, uid)
            try {
                localStorage.removeItem(GUEST_CHAT_HISTORY_KEY)
            } catch {}
        },
        [apiBase]
    )

    const signInWithGoogle = React.useCallback(async () => {
        if (typeof window === "undefined") return
        setBusy(true)
        setError(null)
        trackAuthEvent("signin_attempt", {})

        // Helper: open the relay page and start listening for the session.
        const openRelay = (isInFrame: boolean) => {
            trackAuthEvent("signin_relay_popup", {})
            const state = (typeof crypto !== "undefined" && crypto.randomUUID)
                ? crypto.randomUUID()
                : `${Date.now().toString(36)}-${Math.random().toString(36).slice(2)}`
            const relayUrl = appApiUrl(apiBase, `${APP_API_PATHS.authPopup}?state=${encodeURIComponent(state)}`)

            // When inside an iframe, browsers block window.open unless the iframe has
            // allow="popups". Try window.top.open() first (the parent Framer window
            // has no such restriction), then normal window.open as fallback.
            let win: Window | null = null
            if (isInFrame) {
                try { win = (window.top as Window).open(relayUrl, "_blank") ?? null } catch {}
            }
            if (!win) {
                const wPopup = window.open(relayUrl, "curastem_auth", "popup,width=480,height=600,top=200,left=200")
                win = wPopup ?? window.open(relayUrl, "_blank")
            }
            if (!win) {
                if (isInFrame) {
                    // All popup paths blocked in iframe — KV polling is already running
                    // so the frame will pick up the session as soon as the user manually
                    // opens the relay URL in their browser.
                } else {
                    trackAuthEvent("signin_relay_redirect", {})
                    location.href = relayUrl + "&return_to=" + encodeURIComponent(location.href)
                    return
                }
            }

            let resolved = false
            const resolve = (token: string, user: CurastemUser) => {
                if (resolved) return
                resolved = true
                clearInterval(pollInterval)
                clearTimeout(timer)
                window.removeEventListener("message", msgHandler)
                setBusy(false)
                try {
                    localStorage.setItem(SESSION_TOKEN_KEY, token)
                    localStorage.setItem(CURRENT_USER_KEY, JSON.stringify(user))
                } catch {}
                currentOwnerUid = user.id
                setUser(user)
                setStatus("signed_in")
                trackAuthEvent("signin_success", { uid: user.id, method: "relay" })
                syncAll(user.id).catch((e) => console.warn("post-signin sync failed", e))
            }

            const timer = setTimeout(() => {
                resolved = true
                clearInterval(pollInterval)
                window.removeEventListener("message", msgHandler)
                setBusy(false)
            }, 120_000)

            // Poll KV for the session — works when relay opens in a different
            // browser process and postMessage can't cross the process boundary.
            const pollInterval = setInterval(async () => {
                if (resolved) { clearInterval(pollInterval); return }
                try {
                    const resp = await fetch(
                        appApiUrl(apiBase, `${APP_API_PATHS.authPending}?state=${encodeURIComponent(state)}`),
                        { headers: { "X-Curastem-Client": "web" } }
                    )
                    if (resp.ok) {
                        const data = await resp.json() as { token: string; user: CurastemUser }
                        if (data.token) resolve(data.token, data.user)
                    }
                } catch {}
            }, 2500)

            // postMessage listener — faster path when popup stays in same browser.
            function msgHandler(ev: MessageEvent) {
                if (ev.data?.type !== "curastem_auth") return
                if (ev.data.error) {
                    if (!resolved) {
                        resolved = true
                        clearInterval(pollInterval)
                        clearTimeout(timer)
                        window.removeEventListener("message", msgHandler)
                        setBusy(false)
                        trackAuthEvent("signin_failure", { error: String(ev.data.error).slice(0, 200), method: "relay" })
                    }
                    return
                }
                const { token, user } = ev.data as { token: string; user: CurastemUser }
                resolve(token, user)
            }
            window.addEventListener("message", msgHandler)
        }

        // When running inside an iframe (Framer canvas, any embed), we know Firebase's
        // signInWithPopup will fail with unauthorized-domain before even showing the
        // account picker — and its internal overlay briefly greys out the canvas.
        // Skip straight to the relay instead.
        const inFrame = (() => { try { return window.self !== window.top } catch { return true } })()
        if (inFrame) {
            // Skip Firebase popup entirely in iframes — unauthorized-domain error
            // would grey out the canvas before erroring. Go straight to relay.
            openRelay(true)
            return
        }

        try {
            const fb = await loadFirebaseAuth()
            if (!fb) throw new Error("Firebase SDK failed to load")
            let cred: { user: FirebaseUser }
            try {
                cred = await fb.auth.signInWithPopup(fb.googleProvider)
            } catch (popupErr) {
                const pm = popupErr instanceof Error ? popupErr.message : String(popupErr)
                // Firebase rejects popups on unauthorized domains — open relay instead.
                if (/popup-blocked|popup-not-allowed|operation-not-supported|web-storage-unsupported|unauthorized-domain/i.test(pm)) {
                    openRelay(false)
                    return
                }
                throw popupErr
            }
            const idToken = await cred.user.getIdToken(true)
            const resp = await fetch(appApiUrl(apiBase, APP_API_PATHS.authFirebase), {
                method: "POST",
                credentials: "include",
                headers: {
                    "Content-Type": "application/json",
                    // CSRF defense — see backend requireCsrfHeader(). Any
                    // cross-origin page without our CORS allowlist can't
                    // send custom headers, so this alone stops forged
                    // POSTs even though the cookie is SameSite=None.
                    "X-Curastem-Client": "web",
                },
                body: JSON.stringify({ id_token: idToken }),
            })
            if (!resp.ok) {
                const body = await resp.text()
                throw new Error(`/auth/firebase ${resp.status}: ${body}`)
            }
            const data = (await resp.json()) as {
                user: CurastemUser
                token: string
            }
            // Bearer fallback for Framer preview hosts where the apex cookie
            // can't be read. On curastem.org the cookie works on its own.
            try {
                localStorage.setItem(SESSION_TOKEN_KEY, data.token)
                localStorage.setItem(
                    CURRENT_USER_KEY,
                    JSON.stringify(data.user)
                )
            } catch {}
            currentOwnerUid = data.user.id
            setUser(data.user)
            setStatus("signed_in")
            trackAuthEvent("signin_success", { uid: data.user.id })
            // Best-effort sync; UI stays signed in even if push fails so we
            // don't leave the user in a half-state.
            try {
                await syncAll(data.user.id)
            } catch (err) {
                console.warn("post-signin sync failed", err)
            }
        } catch (err) {
            const msg = err instanceof Error ? err.message : String(err)
            console.error("signInWithGoogle failed", err)
            if (/popup-closed-by-user|cancelled-popup-request|user-cancelled/i.test(msg)) {
                trackAuthEvent("signin_cancelled", {})
            } else {
                trackAuthEvent("signin_failure", { error: msg.slice(0, 200) })
            }
            setError(null)
        } finally {
            setBusy(false)
        }
    }, [apiBase, syncAll])

    const signOut = React.useCallback(async () => {
        if (typeof window === "undefined") return
        setBusy(true)
        try {
            try {
                await appApiFetch(apiBase, APP_API_PATHS.authLogout, { method: "POST" })
            } catch {}
            try {
                const fb = await loadFirebaseAuth()
                if (fb && fb.auth.currentUser) await fb.auth.signOut()
            } catch {}
            // Full wipe of on-device user data. Anything the user wants on
            // another device is already in the cloud; anything that wasn't
            // pushed yet is intentionally sacrificed rather than leaked to
            try {
                localStorage.removeItem(SESSION_TOKEN_KEY)
                localStorage.removeItem(CURRENT_USER_KEY)
                localStorage.removeItem(SYNC_WATERMARK_KEY)
                localStorage.removeItem(SYNC_HYDRATED_KEY)
                localStorage.removeItem(SYNC_QUEUE_KEY)
                for (const k of USER_DATA_LS_KEYS) {
                    localStorage.removeItem(k)
                }
            } catch {}
            currentOwnerUid = null
            trackAuthEvent("signout", {})
            setUser(null)
            setStatus("signed_out")
            // Storage event so the rest of the UI re-reads from (now empty)
            // localStorage without needing a full reload.
            try {
                window.dispatchEvent(new Event("storage"))
            } catch {}
        } finally {
            setBusy(false)
        }
    }, [apiBase])

    return {
        status,
        user,
        signInWithGoogle,
        signOut,
        syncAll,
        busy,
        error,

    }
}

/**
 * Lightweight auth analytics. Dispatches a `CustomEvent` on window and also
 * calls `window.gtag` / `window.dataLayer` when present so Framer's analytics
 * layer and Google Analytics both receive the same signal without us taking
 * a hard dependency on either.
 *
 * We intentionally never send PII (email, name). Just the uid hash when we
 * have one so we can segment aggregates in a dashboard.
 */
function trackAuthEvent(
    name:
        | "signin_attempt"
        | "signin_success"
        | "signin_failure"
        | "signin_cancelled"
        | "signout",
    props: Record<string, unknown>
): void {
    if (typeof window === "undefined") return
    try {
        window.dispatchEvent(
            new CustomEvent("curastem:auth", { detail: { name, ...props } })
        )
    } catch {}
    try {
        const w = window as unknown as {
            gtag?: (...args: unknown[]) => void
            dataLayer?: unknown[]
        }
        if (typeof w.gtag === "function") {
            w.gtag("event", `curastem_${name}`, props)
        } else if (Array.isArray(w.dataLayer)) {
            w.dataLayer.push({ event: `curastem_${name}`, ...props })
        }
    } catch {}
}

/** Fetch with credentials + Bearer fallback from localStorage. */
function authedFetch(
    apiBase: string,
    path: string,
    init?: RequestInit
): Promise<Response> {
    const headers = new Headers(init?.headers || {})
    try {
        const token = localStorage.getItem(SESSION_TOKEN_KEY)
        if (token && !headers.has("Authorization")) {
            headers.set("Authorization", `Bearer ${token}`)
        }
    } catch {}
    if (!headers.has("X-Curastem-Client")) {
        headers.set("X-Curastem-Client", "web")
    }
    return fetch(`${apiBase}${path}`, {
        ...init,
        headers,
        credentials: "include",
    })
}

const APP_API_PATHS = {
    authFirebase: "/auth/firebase",
    authGeminiToken: "/auth/gemini-token",
    geminiLiveProxy: "/proxy/gemini-live",
    authMapsKey: "/auth/maps-key",
    authLogout: "/auth/logout",
    authMe: "/auth/me",
    authPending: "/auth/pending",
    authPopup: "/auth/popup",
    authPrefs: "/auth/me/prefs",
    agentTool: "/agent/tool",
    agentChat: "/agent/chat",
    agentTools: "/agent/tools",
    chats: "/chats",
    docs: "/docs",
    apps: "/apps",
    resume: "/uploads/resume",
    resumeProcess: "/uploads/resume/process",
    syncDelta: "/sync/delta",
    syncPull: "/sync/pull",
    syncPush: "/sync/push",
    syncStream: "/sync/stream",
    uploadAttachment: "/uploads/attachment",
    chat: (chatId: string) => `/chats/${encodeURIComponent(chatId)}`,
    chatMessages: (chatId: string, query = "") =>
        `/chats/${encodeURIComponent(chatId)}/messages${query}`,
    chatTitle: (chatId: string) =>
        `/chats/${encodeURIComponent(chatId)}/title`,
    attachment: (rawKey: string) => `/uploads/attachment/${rawKey}`,
} as const

function appApiFetch(
    apiBase: string,
    path: string,
    init?: RequestInit
): Promise<Response> {
    return authedFetch(apiBase, path, init)
}

function appApiUrl(apiBase: string, path: string): string {
    return `${apiBase}${path}`
}

const DEFAULT_APP_API_BASE = "https://api.curastem.org"

function resolveAppApiBase(apiBase: string | null | undefined): string {
    const trimmed = apiBase?.trim().replace(/\/$/, "")
    if (!trimmed) return DEFAULT_APP_API_BASE
    try {
        const url = new URL(trimmed)
        if (url.protocol === "http:" || url.protocol === "https:") {
            return trimmed
        }
    } catch {}
    return DEFAULT_APP_API_BASE
}

function cloudAgentBrowserContext(): string {
    if (typeof window === "undefined") return "origin=server"
    const online =
        typeof navigator !== "undefined" ? String(navigator.onLine) : "unknown"
    return [
        `origin=${window.location.origin || "unknown"}`,
        `href=${window.location.href || "unknown"}`,
        `referrer=${document.referrer || "none"}`,
        `online=${online}`,
    ].join(" ")
}

