    // --- Resume upload handlers ---

    const handleResumeUpload = React.useCallback(
        async (e: React.ChangeEvent<HTMLInputElement>) => {
            const file = e.target.files?.[0]
            if (!file) return
            if (resumeFileInputRef.current)
                resumeFileInputRef.current.value = ""

            setIsProcessingResume(true)
            setIsResumeHtmlPending(false)
            setIsResumeEditableReady(false)
            try {
                const dataUrl = await new Promise<string>((resolve, reject) => {
                    const reader = new FileReader()
                    reader.onload = () => resolve(reader.result as string)
                    reader.onerror = reject
                    reader.readAsDataURL(file)
                })

                // Use the original filename, strip any extension, force .pdf
                const savedFileName = file.name.replace(/\.[^.]+$/, "") + ".pdf"
                const uploadedResumeFile: ResumeFileState = {
                    name: savedFileName,
                    base64: dataUrl,
                    mimeType: file.type,
                    savedAt: Date.now(),
                }
                const pendingSig = resumeFileSignature(uploadedResumeFile)
                resumeUploadPendingRef.current = true
                if (pendingSig) {
                    try {
                        localStorage.setItem(RESUME_UPLOAD_PENDING_KEY, pendingSig)
                    } catch {}
                }

                // Persist the file itself (always as PDF label even if uploaded as docx)
                clearProfileResumeDocHtml()
                localStorage.removeItem("curastem_resume")
                setResumeFile(uploadedResumeFile)
            } catch {
                // Silently fail — file input resets, no state changes
                setIsProcessingResume(false)
                setIsResumeHtmlPending(false)
            }
        },
        [resumeFileSignature]
    )

    const handleResumeUploadRequest = React.useCallback(() => {
        resumeFileInputRef.current?.click()
    }, [])

    const handleResumeDownload = React.useCallback(async () => {
        haptic.light()
        const html = getProfileResumeDocHtml()?.trim()
        if (html) {
            try {
                const pdfBytes = await docHtmlToOnePagePdfBytes(html, false)
                const blob = new Blob([pdfBytes], { type: "application/pdf" })
                const url = URL.createObjectURL(blob)
                const link = document.createElement("a")
                link.href = url
                const base =
                    resumeFile?.name.replace(/\.[^.]+$/, "").trim() || "Resume"
                link.download = `${base}.pdf`
                document.body.appendChild(link)
                link.click()
                document.body.removeChild(link)
                setTimeout(() => URL.revokeObjectURL(url), 5000)
            } catch (e) {
                console.error("resume PDF export failed:", e)
            }
            setResumeMenuOpen(false)
            return
        }
        if (!resumeFile) return
        const link = document.createElement("a")
        link.href = resumeFile.base64
        link.download = resumeFile.name
        document.body.appendChild(link)
        link.click()
        document.body.removeChild(link)
        setResumeMenuOpen(false)
    }, [resumeFile])

    const handleChatResumeDownload = React.useCallback(
        async (docId?: string) => {
            const doc = docId
                ? chatDocsRef.current.find((item) => item.id === docId)
                : [...chatDocsRef.current]
                      .filter((item) => item.docType === "resume")
                      .sort((a, b) => b.lastEdited - a.lastEdited)[0]

            if (doc?.docType !== "resume" || !doc.content.trim()) {
                console.warn("No synced resume document found for chat download.")
                return
            }

            haptic.light()
            try {
                const pdfBytes = await docHtmlToOnePagePdfBytes(
                    doc.content,
                    false
                )
                const blob = new Blob([pdfBytes as unknown as BlobPart], {
                    type: "application/pdf",
                })
                const url = URL.createObjectURL(blob)
                const link = document.createElement("a")
                const company = doc.docCompany || ""
                link.href = url
                link.download = `${profileNameStem(youName) || "resume"}${
                    company ? `_${company.replace(/\s+/g, "_").slice(0, 30)}` : ""
                }.pdf`
                document.body.appendChild(link)
                link.click()
                document.body.removeChild(link)
                setTimeout(() => URL.revokeObjectURL(url), 5000)
            } catch (e) {
                console.error("resume PDF export failed:", e)
            }
        },
        [youName]
    )

