    React.useEffect(() => {
        let nextSeq = 1
        for (const message of messages) {
            if (typeof message._seq === "number" && message._seq >= nextSeq) {
                nextSeq = message._seq + 1
            }
        }
        nextSeq = Math.max(nextSeq, nextLocalMessageSeqRef.current)

        let changed = false
        const now = Date.now()
        const ordered = messages.map((message, index) => {
            const needsSeq = typeof message._seq !== "number"
            const needsCreatedAt =
                typeof message._createdAt !== "number" &&
                typeof message._serverCreatedAt !== "number"
            if (!needsSeq && !needsCreatedAt) return message
            changed = true
            return {
                ...message,
                ...(needsSeq ? { _seq: nextSeq++ } : {}),
                ...(needsCreatedAt ? { _createdAt: now + index } : {}),
            }
        })

        nextLocalMessageSeqRef.current = nextSeq
        if (changed) setMessages(ordered)
    }, [messages, currentChatId])

