    const generateVideoThumbnail = async (file: File): Promise<string> => {
        return new Promise((resolve) => {
            try {
                const url = URL.createObjectURL(file)
                const video = document.createElement("video")
                video.src = url
                video.muted = true
                video.playsInline = true as any
                const capture = () => {
                    const canvas = document.createElement("canvas")
                    const w = 320
                    const h = Math.max(
                        1,
                        Math.round((video.videoHeight / video.videoWidth) * w)
                    )
                    canvas.width = w
                    canvas.height = h
                    const ctx = canvas.getContext("2d")
                    if (ctx) {
                        ctx.drawImage(video, 0, 0, w, h)
                        const dataUrl = canvas.toDataURL("image/jpeg", 0.8)
                        try {
                            URL.revokeObjectURL(url)
                        } catch {}
                        resolve(dataUrl)
                    } else {
                        resolve("")
                    }
                }
                video.onloadedmetadata = () => {
                    video.currentTime = 1.0
                }
                video.onseeked = () => capture()
                video.onerror = () => {
                    try {
                        URL.revokeObjectURL(url)
                    } catch {}
                    resolve("")
                }
            } catch {
                resolve("")
            }
        })
    }

    
    
    
    const calculateHeightConstraints = React.useCallback(
        (
            cWidth: number,
            cHeight: number,
            _isMobileLayout: boolean,
            _isScreenSharing: boolean,
            _remoteScreenStream: MediaStream | null,
            _isWhiteboardOpen: boolean,
            _isDocOpen: boolean,
            _isAppOpen: boolean,
            _sharedScreenSize: { width: number; height: number } | null
        ) => {

            
            
            
            const numTiles = Math.max(
                2,
                1 + remoteStreams.size + pendingPeerIds.size
            )
            const isContentOpen = hasVideoContent(
                _isScreenSharing,
                _remoteScreenStream,
                _isWhiteboardOpen,
                _isDocOpen,
                _isAppOpen
            )
            const targetRatio = getTargetRatioForTiles(numTiles, isContentOpen)

            let minHeight = MIN_CHAT_HEIGHT

            if (!isContentOpen) {
                let maxVideoHeightNeeded = 0

                if (_isMobileLayout) {
                    
                    const availableWidth = Math.max(0, cWidth - 32)
                    const v_videoHeight = availableWidth / targetRatio
                    maxVideoHeightNeeded = v_videoHeight * 2 + 8
                } else {
                    
                    const availableWidthPerVideo = (cWidth - 32 - 8) / 2
                    maxVideoHeightNeeded = availableWidthPerVideo / targetRatio
                }

                const calculatedMinChatHeight =
                    cHeight - 40 - maxVideoHeightNeeded
                minHeight = Math.max(MIN_CHAT_HEIGHT, calculatedMinChatHeight)
            } else {
                
                const contentDims =
                    getContentDimensions(
                        _isWhiteboardOpen,
                        _isDocOpen,
                        _isAppOpen,
                        _isMobileLayout
                    ) ?? _sharedScreenSize
                const activeWidth = contentDims?.width
                const activeHeight = contentDims?.height

                if (activeWidth && activeHeight) {
                    const videoRatio = activeWidth / activeHeight
                    const availableWidth = Math.max(0, cWidth - 32)
                    const maxVideoHeightNeeded = availableWidth / videoRatio

                    let topRowHeight = 140
                    if (_isMobileLayout) {
                        const tileW = Math.max(0, (availableWidth - 8) / 2)
                        topRowHeight = tileW / (4 / 3)
                    }
                    const chromeHeight = 24 + 16 + topRowHeight + 8

                    const calculatedMinChatHeight =
                        cHeight - chromeHeight - maxVideoHeightNeeded
                    minHeight = Math.max(
                        MIN_CHAT_HEIGHT,
                        calculatedMinChatHeight
                    )
                }
            }

            let maxHeight = cHeight - MIN_CHAT_HEIGHT 

            if (_isMobileLayout && !isContentOpen) {
                const minVideoSectionHeight = 80
                maxHeight = Math.max(
                    MIN_CHAT_HEIGHT,
                    cHeight - 40 - minVideoSectionHeight
                )
            }

            if (isContentOpen) {
                let topRowHeight = 140
                if (_isMobileLayout) {
                    const availableW = Math.max(0, cWidth - 32)

                    
                    
                    
                    

                    
                    const tileW = (availableW - 8) / 2
                    topRowHeight = tileW / targetRatio

                    if (_isScreenSharing || !!_remoteScreenStream) {
                        topRowHeight += 248
                    }
                } else if (_isScreenSharing || !!_remoteScreenStream) {
                    
                    topRowHeight += 248
                }

                const chromeHeight = 24 + 16 + topRowHeight + 8
                const minVideoHeight = 0

                maxHeight = cHeight - chromeHeight - minVideoHeight
            }

            return { minHeight, maxHeight }
        },
        [remoteStreams, pendingPeerIds]
    )

    
    
