    const mobileToolGestureAxisRef = React.useRef<null | "x" | "y">(null)
    const [mobileToolGestureAxis, setMobileToolGestureAxis] = React.useState<
        null | "x" | "y"
    >(null)
    const lockMobileToolGesture = React.useCallback(
        (axis: null | "x" | "y") => {
            mobileToolGestureAxisRef.current = axis
            setMobileToolGestureAxis(axis)
        },
        []
    )

    
    const closeJobDetailRef = React.useRef(closeJobDetail)
    closeJobDetailRef.current = closeJobDetail
    React.useEffect(() => {
        if (!isMobileLayout || !isMapOpen || !isJobOpen) return
        const sheet = document.querySelector(
            ".MapJobOverlay"
        ) as HTMLElement | null
        if (!sheet) return
        const pullY = mapJobDragYRef.current
        let lastY = 0,
            startY = 0,
            startX = 0,
            pressed = false
        let activePointerId = -1,
            pullCaptureActive = false
        const scrollEl = () =>
            sheet.querySelector("[data-pull-scroll]") as HTMLElement | null
        const GESTURE_MIN = 10
        const releaseCap = () => {
            if (!pullCaptureActive || activePointerId < 0) return
            try {
                if (sheet.hasPointerCapture(activePointerId))
                    sheet.releasePointerCapture(activePointerId)
            } catch {
                
            }
            pullCaptureActive = false
            activePointerId = -1
        }
        const settle = () => {
            releaseCap()
            pressed = false
            lockMobileToolGesture(null)
            if (pullY.get() < 88) {
                animate(pullY, 0, {
                    type: "spring",
                    stiffness: 420,
                    damping: 38,
                })
            } else {
                closeJobDetailRef.current()
            }
        }
        const onDown = (e: PointerEvent) => {
            if (e.pointerType === "mouse" && e.button !== 0) return
            pressed = true
            pullCaptureActive = false
            activePointerId = e.pointerId
            lockMobileToolGesture(null)
            startX = e.clientX
            startY = e.clientY
            lastY = e.clientY
        }
        const onMove = (e: PointerEvent) => {
            if (!pressed) return
            let axis = mobileToolGestureAxisRef.current
            if (axis === "x") return
            const adx = Math.abs(e.clientX - startX),
                ady = Math.abs(e.clientY - startY)
            if (axis === null) {
                if (adx < GESTURE_MIN && ady < GESTURE_MIN) return
                lockMobileToolGesture(adx > ady * 1.35 ? "x" : "y")
                axis = mobileToolGestureAxisRef.current
                if (axis === "x") return
            }
            const dy = e.clientY - lastY
            lastY = e.clientY
            const py = pullY.get()
            const sc = scrollEl()
            const atTop = sc == null || sc.scrollTop <= 1
            if (!(py > 0 || (atTop && dy > 0))) return
            if (!pullCaptureActive) {
                try {
                    sheet.setPointerCapture(e.pointerId)
                    pullCaptureActive = true
                    activePointerId = e.pointerId
                } catch {
                    
                }
            }
            pullY.set(Math.max(0, py + dy))
            if (e.pointerType === "touch" && e.cancelable) e.preventDefault()
        }
        const onTouchMove = (e: TouchEvent) => {
            if (pullY.get() > 2 && e.cancelable) e.preventDefault()
        }
        sheet.addEventListener("pointerdown", onDown)
        sheet.addEventListener("pointermove", onMove)
        sheet.addEventListener("pointerup", settle)
        sheet.addEventListener("pointercancel", settle)
        sheet.addEventListener("touchmove", onTouchMove, { passive: false })
        return () => {
            releaseCap()
            sheet.removeEventListener("pointerdown", onDown)
            sheet.removeEventListener("pointermove", onMove)
            sheet.removeEventListener("pointerup", settle)
            sheet.removeEventListener("pointercancel", settle)
            sheet.removeEventListener("touchmove", onTouchMove)
        }
    }, [isMobileLayout, isMapOpen, isJobOpen, lockMobileToolGesture]) 

