    const handleWhiteboardPointerMove = React.useCallback(
        (e: React.PointerEvent) => {
            if (!isWhiteboardOpen || dataConnectionsRef.current.size === 0)
                return

            const now = Date.now()
            if (now - lastCursorUpdate.current < 50) return 
            lastCursorUpdate.current = now

            if (editorRef.current) {
                
                const container = editorRef.current.getContainer()
                if (!container) return

                const rect = container.getBoundingClientRect()
                
                const pagePoint = editorRef.current.screenToPage({
                    x: e.clientX - rect.left,
                    y: e.clientY - rect.top,
                })

                broadcastData({
                    type: "cursor-update",
                    payload: {
                        x: pagePoint.x,
                        y: pagePoint.y,
                        color: myCursorColor.current,
                    },
                })
            } else if (whiteboardContainerRef.current) {
                const rect =
                    whiteboardContainerRef.current.getBoundingClientRect()
                const x = (e.clientX - rect.left) / rect.width
                const y = (e.clientY - rect.top) / rect.height

                
                if (x >= 0 && x <= 1 && y >= 0 && y <= 1) {
                    broadcastData({
                        type: "cursor-update",
                        payload: { x, y, color: myCursorColor.current },
                    })
                }
            }
        },
        [isWhiteboardOpen]
    )

    const toggleScreenShare = React.useCallback(async () => {
        if (isScreenSharing) {
            stopLocalScreenShare()
        } else {
            
            /** if (isWhiteboardOpen) { setIsWhiteboardOpen(false) // Notify peer to close whiteboard broadcastData({ type */

            
            try {
                
                
                if (
                    !navigator.mediaDevices ||
                    !navigator.mediaDevices.getDisplayMedia
                ) {
                    alert(
                        "Screen sharing is not supported on this device or browser."
                    )
                    return
                }

                
                const screenStream =
                    await navigator.mediaDevices.getDisplayMedia({
                        video: true,
                        audio: false, 
                    })
                screenStreamRef.current = screenStream
                const screenTrack = screenStream.getVideoTracks()[0]

                screenTrack.onended = () => {
                    stopLocalScreenShare()
                }

                
                if (activeCalls.current.size > 0) {
                    activeCalls.current.forEach((call, peerId) => {
                        log(`Starting screen share call to ${peerId}...`)
                        const screenCall = peerInstance.current.call(
                            peerId,
                            screenStream,
                            {
                                metadata: { type: "screen" },
                            }
                        )
                        screenCall.on("error", (err: any) =>
                            log(`Sender Screen Call Error to ${peerId}: ${err}`)
                        )
                        screenCallsRef.current.set(peerId, screenCall)

                        
                        if (!screenCallRef.current)
                            screenCallRef.current = screenCall
                    })
                } else if (activeCall.current && activeCall.current.peer) {
                    
                    const peerId = activeCall.current.peer
                    log(`Starting screen share call to ${peerId}...`)
                    const call = peerInstance.current.call(
                        peerId,
                        screenStream,
                        {
                            metadata: { type: "screen" },
                        }
                    )
                    call.on("error", (err: any) =>
                        log(`Sender Screen Call Error: ${err}`)
                    )
                    screenCallRef.current = call
                    screenCallsRef.current.set(peerId, call)
                }

                setIsScreenSharing(true)
            } catch (err: any) {
                console.error("Screen share error:", err)
                if (err.name === "NotAllowedError") {
                    
                } else {
                    alert(`Screen share failed: ${err.message || err}`)
                }
            }
        }
    }, [isScreenSharing, isWhiteboardOpen, stopLocalScreenShare])

